import type { CareerQuestion } from "./rrt-questions";

export const cardiacSonographerQuestions: CareerQuestion[] = [
  { id: "cs-001", stem: "The left ventricle is separated from the left atrium by:", options: ["The mitral valve","The tricuspid valve","The aortic valve","The pulmonic valve"], correctIndex: 0, rationale: "The mitral valve (bicuspid valve) separates the LA from the LV. It has anterior and posterior leaflets attached to papillary muscles via chordae tendineae.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Valves" },
  { id: "cs-002", stem: "The right ventricle receives blood from:", options: ["The right atrium through the tricuspid valve","The left atrium through the mitral valve","The pulmonary veins","The aorta"], correctIndex: 0, rationale: "The RV receives deoxygenated blood from the RA through the tricuspid valve and pumps it through the pulmonic valve into the pulmonary artery.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Chambers" },
  { id: "cs-003", stem: "The coronary sinus drains into:", options: ["The right atrium","The left atrium","The left ventricle","The pulmonary artery"], correctIndex: 0, rationale: "The coronary sinus is the main venous drainage of the heart, collecting blood from the coronary veins and emptying into the posterior right atrium near the IVC orifice.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Coronary Anatomy" },
  { id: "cs-004", stem: "The moderator band is located in:", options: ["The right ventricle","The left ventricle","The right atrium","The left atrium"], correctIndex: 0, rationale: "The moderator band is a muscular band crossing the RV cavity from the interventricular septum to the anterior papillary muscle. It carries the right bundle branch.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "RV Anatomy" },
  { id: "cs-005", stem: "The aortic valve normally has:", options: ["Three cusps (right coronary, left coronary, and non-coronary)","Two cusps","Four cusps","One cusp"], correctIndex: 0, rationale: "The aortic valve is a trileaflet semilunar valve with right coronary (RC), left coronary (LC), and non-coronary (NC) cusps. Bicuspid aortic valve is the most common congenital valve anomaly.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Valves" },
  { id: "cs-006", stem: "The mitral valve apparatus includes:", options: ["Annulus, anterior and posterior leaflets, chordae tendineae, and papillary muscles","Only the leaflets","Only the annulus","Only the papillary muscles"], correctIndex: 0, rationale: "The mitral apparatus is a complex unit: fibrous annulus, anterior and posterior leaflets (with A1-A3 and P1-P3 scallops), chordae tendineae, and anterolateral/posteromedial papillary muscles.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Mitral Anatomy" },
  { id: "cs-007", stem: "The interventricular septum contains:", options: ["The conduction system including the bundle of His and bundle branches","No important structures","Only coronary arteries","Only connective tissue"], correctIndex: 0, rationale: "The IVS contains the bundle of His and its branches (right and left bundle branches) that carry electrical signals from the AV node to the ventricles.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Conduction System" },
  { id: "cs-008", stem: "The left anterior descending artery (LAD) supplies:", options: ["The anterior wall and anterior septum of the left ventricle","The posterior wall","The right ventricle","The right atrium"], correctIndex: 0, rationale: "The LAD courses in the anterior interventricular groove, supplying the anterior wall, anterior 2/3 of the IVS, and LV apex. LAD occlusion causes anterior STEMI.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Coronary Anatomy" },
  { id: "cs-009", stem: "The pulmonary veins normally drain into:", options: ["The left atrium","The right atrium","The IVC","The coronary sinus"], correctIndex: 0, rationale: "Four pulmonary veins (2 right, 2 left) drain oxygenated blood from the lungs into the left atrium. Anomalous pulmonary venous return is a congenital abnormality.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Anatomy" },
  { id: "cs-010", stem: "The eustachian valve is a remnant of:", options: ["The inferior vena cava valve, located in the right atrium near the IVC orifice","The foramen ovale","The ductus arteriosus","The mitral valve"], correctIndex: 0, rationale: "The eustachian valve is a vestigial remnant of the embryonic IVC valve in the RA. It may be prominent and mistaken for a mass or vegetation. It is a normal variant.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Normal Variants" },
  { id: "cs-011", stem: "The parasternal long-axis (PLAX) view displays:", options: ["The LV, LA, mitral valve, aortic valve, and proximal aorta","The RV and RA","Four chambers","The aortic arch"], correctIndex: 0, rationale: "PLAX shows the LV (anterior septum and posterior wall), LA, LVOT, aortic valve, proximal ascending aorta, mitral valve, and a portion of the RV.", difficulty: 1, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-012", stem: "The apical four-chamber view is obtained by:", options: ["Placing the transducer at the cardiac apex with the beam directed toward the right shoulder","Placing at the left parasternal border","Subcostal approach","Suprasternal approach"], correctIndex: 0, rationale: "Apical 4-chamber: transducer at the apex, marker to patient's left. Shows all 4 chambers, both AV valves, and the interatrial and interventricular septa.", difficulty: 1, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-013", stem: "The parasternal short-axis view at the level of the papillary muscles shows:", options: ["The LV in cross-section with the posteromedial and anterolateral papillary muscles","The aortic valve","The mitral valve leaflets","The ascending aorta"], correctIndex: 0, rationale: "PSAX at papillary level: circular LV cross-section with two papillary muscles (anterolateral and posteromedial) protruding into the cavity. Used for LV wall motion assessment.", difficulty: 1, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-014", stem: "The subcostal view is particularly useful in patients with:", options: ["Emphysema or difficult parasternal/apical windows due to hyperinflated lungs","Only pediatric patients","Only obese patients","Only intubated patients"], correctIndex: 0, rationale: "The subcostal window uses the liver as an acoustic window. It's valuable when parasternal/apical windows are poor (COPD, mechanical ventilation) and for IVC/interatrial septum evaluation.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Alternative Views" },
  { id: "cs-015", stem: "The suprasternal notch view displays:", options: ["The aortic arch, great vessels, and sometimes the left atrium","The mitral valve","The LV apex","The coronary arteries"], correctIndex: 0, rationale: "Suprasternal view: aortic arch, innominate artery, left common carotid, left subclavian, descending aorta, and occasionally the LA posterior to the aorta. Used for coarctation assessment.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-016", stem: "In the apical 5-chamber view, the additional structure compared to the 4-chamber is:", options: ["The aortic valve and proximal aorta (LVOT)","The pulmonary artery","The IVC","The coronary sinus"], correctIndex: 0, rationale: "Apical 5-chamber: tilt the transducer anteriorly from the 4-chamber view to add the LVOT and aortic valve as the '5th chamber.' Used for LVOT measurements and aortic regurgitation.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-017", stem: "The parasternal short-axis view at the aortic valve level shows:", options: ["The aortic valve with its three cusps, LA, RA, TV, RV, RVOT, and pulmonic valve","Only the LV","Only the mitral valve","Only the LA"], correctIndex: 0, rationale: "PSAX at AV level: AV appears as a 'Mercedes-Benz sign' with 3 cusps. Also shows LA, RA, TV, interatrial septum, RVOT, and pulmonic valve.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-018", stem: "The right ventricular inflow view is obtained from:", options: ["A modified parasternal long-axis or apical view focused on the RV, RA, and tricuspid valve","The suprasternal notch","The subcostal approach only","The apical 2-chamber view"], correctIndex: 0, rationale: "RV inflow view: modify PLAX by tilting toward the right heart, showing RA, TV, and RV. Also obtained from the apical view with medial angulation. Essential for TV assessment.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Specialized Views" },
  { id: "cs-019", stem: "The apical 2-chamber view shows:", options: ["The LA, mitral valve, and LV with inferior and anterior walls","All four chambers","The RV and RA","The aortic valve"], correctIndex: 0, rationale: "Apical 2-chamber: rotate 60° counterclockwise from 4-chamber. Shows LA, MV, and LV (inferior wall = near field, anterior wall = far field). No RV or RA visible.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-020", stem: "The apical 3-chamber (long-axis) view shows:", options: ["The LA, LV, LVOT, and aortic valve — similar to PLAX but from the apex","Only the LV","Only the RV","The tricuspid valve"], correctIndex: 0, rationale: "Apical 3-chamber: rotate further from 2-chamber to see LA, MV, LV (anteroseptal and posterolateral walls), LVOT, and aortic valve. Used for aortic and mitral assessment.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Standard Views" },
  { id: "cs-021", stem: "The simplified Bernoulli equation is:", options: ["ΔP = 4v² (pressure gradient = 4 times the velocity squared)","ΔP = 2v","ΔP = v/2","ΔP = 8v²"], correctIndex: 0, rationale: "The simplified Bernoulli equation converts Doppler velocity to pressure gradient: ΔP (mmHg) = 4 × v² (m/s). Assumes proximal velocity is negligible.", difficulty: 1, category: "Cardiac Hemodynamics & Doppler", topic: "Bernoulli Equation" },
  { id: "cs-022", stem: "The continuity equation is based on:", options: ["Conservation of mass — flow volume must be equal at two points in series","Conservation of energy","The Doppler equation","The Frank-Starling law"], correctIndex: 0, rationale: "Continuity equation: Flow₁ = Flow₂. Therefore, A₁ × VTI₁ = A₂ × VTI₂. Used to calculate aortic valve area: AVA = (LVOT area × LVOT VTI) / AV VTI.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Continuity Equation" },
  { id: "cs-023", stem: "Stroke volume is calculated by:", options: ["LVOT area × LVOT VTI (velocity time integral)","Heart rate × blood pressure","Peak velocity × time","LV mass × ejection fraction"], correctIndex: 0, rationale: "SV = LVOT CSA × LVOT VTI. LVOT CSA = π × (LVOT diameter/2)². LVOT diameter measured in PLAX. LVOT VTI from PW Doppler in apical 5-chamber.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Cardiac Output" },
  { id: "cs-024", stem: "Cardiac output is calculated as:", options: ["Stroke volume × heart rate","Peak velocity × LVOT area","Mean pressure × resistance","End-diastolic volume × ejection fraction"], correctIndex: 0, rationale: "CO = SV × HR. SV from LVOT CSA × LVOT VTI. Normal CO: 4-8 L/min. Cardiac index = CO/BSA (normal: 2.5-4.0 L/min/m²).", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Cardiac Output" },
  { id: "cs-025", stem: "The LVOT diameter for hemodynamic calculations is measured in:", options: ["The parasternal long-axis view during mid-systole, inner edge to inner edge","The apical 4-chamber view","The subcostal view","The suprasternal view"], correctIndex: 0, rationale: "LVOT diameter: measured in PLAX at mid-systole, from inner edge to inner edge at the aortic annulus level. Critical measurement — errors are squared in area calculation.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Hemodynamic Measurements" },
  { id: "cs-026", stem: "PW Doppler of the LVOT is obtained from:", options: ["The apical 5-chamber view with the sample volume placed just proximal to the aortic valve","The PLAX view","The PSAX view at the AV level","The subcostal view"], correctIndex: 0, rationale: "LVOT PW Doppler: apical 5-chamber, sample volume ~5 mm proximal to the AV in the LVOT. Used for SV, CO calculations, and the continuity equation.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Doppler Technique" },
  { id: "cs-027", stem: "CW Doppler through the aortic valve is used to measure:", options: ["Peak and mean pressure gradients across the valve","LVOT velocity","LA pressure","RV pressure"], correctIndex: 0, rationale: "CW Doppler captures the highest velocity across the AV. Peak gradient = 4 × Vpeak². Mean gradient = traced envelope average. Used for aortic stenosis severity grading.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Aortic Stenosis Assessment" },
  { id: "cs-028", stem: "The deceleration time (DT) of the E wave is measured:", options: ["From the peak of the E wave to the baseline extrapolation of its deceleration slope","From the A wave peak to baseline","From start to end of systole","From R-wave to T-wave on ECG"], correctIndex: 0, rationale: "E-wave DT: from E-wave peak to extrapolated baseline of deceleration slope. Normal: 160-240 ms. Short DT (<160 ms) suggests restrictive filling. Prolonged DT (>240 ms) suggests impaired relaxation.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Diastolic Assessment" },
  { id: "cs-029", stem: "The E/A ratio in a normal young adult is:", options: ["E/A > 1 (E wave is taller than A wave)","E/A < 0.5","E/A = 0","E/A > 3"], correctIndex: 0, rationale: "Normal E/A: >1 (usually 1-2). E = early passive filling, A = atrial contraction. Impaired relaxation: E/A <0.8. Pseudonormal: E/A 0.8-2. Restrictive: E/A >2.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Diastolic Filling" },
  { id: "cs-030", stem: "The myocardial performance index (Tei index) evaluates:", options: ["Combined systolic and diastolic function — (IVCT + IVRT) / ET","Only systolic function","Only diastolic function","Only valve function"], correctIndex: 0, rationale: "Tei index = (IVCT + IVRT) / ejection time. Normal: <0.40 (LV), <0.28 (RV). Higher values indicate worse global function. Advantage: not affected by HR or loading conditions.", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "Global Function" },
  { id: "cs-031", stem: "The PISA method (Proximal Isovelocity Surface Area) is used to:", options: ["Quantify regurgitant flow by measuring the convergence zone proximal to the regurgitant orifice","Measure stenotic jet velocity","Calculate cardiac output","Assess wall motion"], correctIndex: 0, rationale: "PISA quantifies regurgitation: EROA = (2π × r² × aliasing velocity) / peak regurgitant velocity. Regurgitant volume = EROA × regurgitant VTI. Used for MR and AR quantification.", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "Regurgitation Assessment" },
  { id: "cs-032", stem: "dP/dt is a measure of:", options: ["LV contractility — the rate of pressure rise during isovolumic contraction","Diastolic function","Valve area","Cardiac output"], correctIndex: 0, rationale: "dP/dt: rate of LV pressure increase (mmHg/s). Measured from MR CW Doppler jet: time between 1 and 3 m/s velocities. dP/dt = 32/(time in seconds). Normal >1200 mmHg/s.", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "Systolic Function" },
  { id: "cs-033", stem: "Pulmonary artery systolic pressure (PASP) is estimated by:", options: ["4 × (TR peak velocity)² + estimated RAP","4 × (MR peak velocity)²","LVOT velocity squared","Aortic valve gradient"], correctIndex: 0, rationale: "PASP = 4 × (TR Vmax)² + RAP. RAP estimated from IVC size/collapsibility. Normal PASP <35 mmHg. Elevated PASP suggests pulmonary hypertension.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Right Heart Assessment" },
  { id: "cs-034", stem: "Right atrial pressure (RAP) is estimated from:", options: ["IVC diameter and respiratory variation — normal IVC <2.1 cm with >50% collapse = RAP 3 mmHg","Heart rate","Blood pressure","Aortic valve gradient"], correctIndex: 0, rationale: "RAP estimation: IVC <2.1 cm + >50% inspiratory collapse = 3 mmHg. IVC >2.1 cm + <50% collapse = 15 mmHg. Intermediate scenarios = 8 mmHg.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Right Heart Assessment" },
  { id: "cs-035", stem: "The hepatic vein flow pattern normally shows:", options: ["Systolic forward flow, diastolic forward flow, and a-wave reversal with atrial contraction","Continuous forward flow","Only systolic flow","Complete flow reversal"], correctIndex: 0, rationale: "Normal HV: forward flow in systole (S) and diastole (D), with brief reversal during atrial contraction (a-wave). Changes in this pattern reflect RA pressure and TR severity.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Venous Flow Patterns" },
  { id: "cs-036", stem: "Vena contracta width in mitral regurgitation is measured:", options: ["At the narrowest portion of the regurgitant jet just downstream of the mitral valve orifice","At the widest part of the jet in the LA","At the tip of the leaflets","At the annulus level"], correctIndex: 0, rationale: "Vena contracta: the narrowest jet width immediately distal to the regurgitant orifice. MR: <3 mm = mild, 3-6.9 mm = moderate, ≥7 mm = severe. Measured in PLAX or zoomed view.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Regurgitation Quantification" },
  { id: "cs-037", stem: "Severe aortic stenosis is defined by:", options: ["Peak velocity ≥4.0 m/s, mean gradient ≥40 mmHg, or AVA ≤1.0 cm²","Peak velocity 2.0 m/s","Mean gradient 20 mmHg","AVA 2.5 cm²"], correctIndex: 0, rationale: "Severe AS criteria: peak velocity ≥4.0 m/s, mean gradient ≥40 mmHg, AVA ≤1.0 cm² (or indexed ≤0.6 cm²/m²). Moderate: Vpeak 3.0-4.0, gradient 20-40, AVA 1.0-1.5.", difficulty: 2, category: "Valvular Heart Disease", topic: "Aortic Stenosis" },
  { id: "cs-038", stem: "The most common cause of aortic stenosis in patients over 70 is:", options: ["Degenerative calcific aortic stenosis","Rheumatic heart disease","Bicuspid aortic valve","Endocarditis"], correctIndex: 0, rationale: "Degenerative calcific AS (senile AS) is the most common cause in elderly patients. Calcification and fibrosis stiffen the cusps. Bicuspid AV is the most common cause in patients <70.", difficulty: 2, category: "Valvular Heart Disease", topic: "AS Etiology" },
  { id: "cs-039", stem: "Aortic regurgitation severity is assessed by:", options: ["Jet width/LVOT ratio, vena contracta, pressure half-time, holodiastolic flow reversal in descending aorta, and EROA","Only visual assessment of jet size","Only the peak velocity of the jet","Only LV size"], correctIndex: 0, rationale: "AR severity: VC ≥6 mm, jet width/LVOT >65%, PHT <200 ms, holodiastolic descending aortic flow reversal, EROA ≥0.30 cm² all indicate severe AR.", difficulty: 2, category: "Valvular Heart Disease", topic: "Aortic Regurgitation" },
  { id: "cs-040", stem: "Mitral valve prolapse is defined as:", options: ["Superior displacement of one or both mitral leaflets ≥2 mm above the annular plane in the PLAX view","Normal mitral valve motion","Mitral stenosis","Mitral annular calcification"], correctIndex: 0, rationale: "MVP: ≥2 mm systolic displacement of leaflet(s) above the mitral annular plane in PLAX. May be associated with MR. Classic MVP has leaflet thickness ≥5 mm.", difficulty: 2, category: "Valvular Heart Disease", topic: "Mitral Valve Prolapse" },
  { id: "cs-041", stem: "Severe mitral regurgitation criteria include:", options: ["Vena contracta ≥7 mm, EROA ≥0.40 cm², regurgitant volume ≥60 mL, regurgitant fraction ≥50%","Vena contracta 2 mm","EROA 0.10 cm²","Regurgitant volume 20 mL"], correctIndex: 0, rationale: "Severe MR: VC ≥7 mm, EROA ≥0.40 cm², RVol ≥60 mL, RF ≥50%, dense triangular CW signal, E-wave dominant (>1.2 m/s), systolic pulmonary vein reversal.", difficulty: 2, category: "Valvular Heart Disease", topic: "Mitral Regurgitation" },
  { id: "cs-042", stem: "Mitral stenosis is most commonly caused by:", options: ["Rheumatic heart disease","Degenerative calcification","Mitral valve prolapse","Endocarditis"], correctIndex: 0, rationale: "Rheumatic heart disease is the most common cause of mitral stenosis. It causes commissural fusion, chordal shortening, and leaflet thickening. The 'fish-mouth' or 'hockey stick' appearance is characteristic.", difficulty: 2, category: "Valvular Heart Disease", topic: "Mitral Stenosis" },
  { id: "cs-043", stem: "The Wilkins score for mitral stenosis evaluates:", options: ["Leaflet mobility, thickening, calcification, and subvalvular apparatus for balloon valvuloplasty suitability","Only valve area","Only pressure gradient","Only leaflet mobility"], correctIndex: 0, rationale: "Wilkins score (0-16): grades mobility, thickening, calcification, and subvalvular disease (0-4 each). Score ≤8 favors percutaneous balloon mitral valvuloplasty.", difficulty: 3, category: "Valvular Heart Disease", topic: "MS Assessment" },
  { id: "cs-044", stem: "Mitral valve area in mitral stenosis can be calculated by:", options: ["Pressure half-time method: MVA = 220/PHT","Bernoulli equation directly","Continuity equation for MV","LVOT area measurement"], correctIndex: 0, rationale: "PHT method: MVA = 220/PHT (ms). Mild MS: MVA >1.5 cm². Moderate: 1.0-1.5 cm². Severe: <1.0 cm². Also measured by planimetry in PSAX.", difficulty: 2, category: "Valvular Heart Disease", topic: "MS Quantification" },
  { id: "cs-045", stem: "Infective endocarditis vegetation on echo appears as:", options: ["An oscillating mass attached to a valve leaflet, typically on the upstream side","A calcified nodule on the aortic root","A smooth thickening of the valve annulus","A pericardial effusion"], correctIndex: 0, rationale: "Vegetations: irregularly shaped, oscillating, echogenic masses on valve leaflets. Typically on the atrial side of AV valves and ventricular side of semilunar valves (upstream = low pressure side).", difficulty: 2, category: "Valvular Heart Disease", topic: "Endocarditis" },
  { id: "cs-046", stem: "Tricuspid regurgitation velocity is used to estimate:", options: ["Pulmonary artery systolic pressure via the simplified Bernoulli equation + RAP","LV systolic pressure","Aortic valve area","Mitral valve gradient"], correctIndex: 0, rationale: "PASP = 4(TR Vmax)² + RAP. TR velocity is the most commonly used noninvasive estimate of pulmonary artery pressure. Normal TR velocity <2.8 m/s.", difficulty: 2, category: "Valvular Heart Disease", topic: "Tricuspid Valve" },
  { id: "cs-047", stem: "Prosthetic valve assessment by echo requires:", options: ["Evaluating gradient, effective orifice area, regurgitation pattern, and leaflet/disc motion","Only visual inspection","Only color Doppler","Only M-mode"], correctIndex: 0, rationale: "Prosthetic valve assessment: mean gradient, DVI (Doppler velocity index), effective orifice area, washing jets (normal small regurgitation), pathologic regurgitation, and leaflet/disc motion.", difficulty: 3, category: "Valvular Heart Disease", topic: "Prosthetic Valves" },
  { id: "cs-048", stem: "A flail mitral valve leaflet on echo shows:", options: ["A leaflet tip that moves into the LA during systole due to chordal rupture","Normal coaptation","Leaflet restriction","Calcified leaflets"], correctIndex: 0, rationale: "Flail leaflet: a portion of the leaflet everts into the LA during systole due to ruptured chordae tendineae. This causes severe, eccentric MR. The ruptured chordae may be visible.", difficulty: 2, category: "Valvular Heart Disease", topic: "Mitral Pathology" },
  { id: "cs-049", stem: "Pulmonic stenosis on echo shows:", options: ["Thickened/domed pulmonic valve with increased velocity on CW Doppler and RV hypertrophy","Normal pulmonic valve","Left heart enlargement","Aortic root dilation"], correctIndex: 0, rationale: "PS: thickened/domed leaflets in systole, peak velocity >3 m/s (moderate) or >4 m/s (severe), RVH, and possible post-stenotic PA dilation.", difficulty: 2, category: "Valvular Heart Disease", topic: "Pulmonic Valve" },
  { id: "cs-050", stem: "Normal left ventricular ejection fraction (LVEF) is:", options: ["55-70%","30-40%","20-30%","80-90%"], correctIndex: 0, rationale: "Normal LVEF: 55-70%. Mildly reduced: 41-54%. Moderately reduced: 30-40%. Severely reduced: <30%. Measured by biplane Simpson's (method of discs).", difficulty: 1, category: "LV Systolic Function Assessment", topic: "EF Assessment" },
  { id: "cs-051", stem: "The biplane Simpson's method (method of discs) for LVEF:", options: ["Traces the LV endocardial border in apical 4-chamber and 2-chamber views at end-diastole and end-systole","Uses M-mode measurements only","Requires 3D imaging","Uses PSAX only"], correctIndex: 0, rationale: "Simpson's biplane: trace endocardial borders in A4C and A2C at ED and ES. The LV is divided into stacked discs. Volume = sum of disc volumes. LVEF = (EDV-ESV)/EDV × 100.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "EF Measurement" },
  { id: "cs-052", stem: "Regional wall motion abnormalities (RWMA) indicate:", options: ["Coronary artery disease with ischemic or infarcted myocardium","Normal cardiac function","Valvular disease only","Pericardial disease only"], correctIndex: 0, rationale: "RWMAs correspond to coronary territories: anterior/septal = LAD, lateral = LCx, inferior = RCA. Grading: normal, hypokinesis, akinesis, dyskinesis, aneurysm.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "Wall Motion" },
  { id: "cs-053", stem: "TAPSE (Tricuspid Annular Plane Systolic Excursion) measures:", options: ["RV longitudinal systolic function — the amount of descent of the tricuspid annulus toward the apex","LV function","Aortic valve excursion","Mitral valve excursion"], correctIndex: 0, rationale: "TAPSE: M-mode through the lateral tricuspid annulus measuring systolic descent. Normal ≥17 mm. <17 mm suggests RV systolic dysfunction. Simple and reproducible.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "RV Function" },
  { id: "cs-054", stem: "Fractional shortening (FS) is calculated from:", options: ["M-mode measurements: FS = (LVEDD - LVESD) / LVEDD × 100%","Doppler measurements","2D planimetry","3D volumetric analysis"], correctIndex: 0, rationale: "FS uses M-mode diameters at the tips of the mitral leaflets. Normal: 25-45%. Limitations: assumes uniform contraction, inaccurate with RWMAs or asymmetric LV geometry.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "M-Mode Assessment" },
  { id: "cs-055", stem: "Global longitudinal strain (GLS) measures:", options: ["LV myocardial deformation using speckle tracking — normal GLS is approximately -18% to -22%","LV volume","Heart rate","Valve function"], correctIndex: 0, rationale: "GLS measures myocardial shortening in the longitudinal direction using speckle tracking echocardiography. More sensitive than LVEF for detecting subclinical systolic dysfunction.", difficulty: 3, category: "LV Systolic Function Assessment", topic: "Advanced Assessment" },
  { id: "cs-056", stem: "A wall motion score index (WMSI) of 1.0 indicates:", options: ["All segments are normal (normokinesis)","Severe global dysfunction","Moderate dysfunction","Mild hypokinesis"], correctIndex: 0, rationale: "WMSI = sum of individual wall scores / number of scored segments. Scoring: 1=normal, 2=hypokinesis, 3=akinesis, 4=dyskinesis, 5=aneurysm. WMSI 1.0 = all normal.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "Wall Motion Scoring" },
  { id: "cs-057", stem: "S' (tissue Doppler systolic velocity) at the mitral annulus measures:", options: ["LV longitudinal systolic function — normal ≥6 cm/s (septal) or ≥8 cm/s (lateral)","Diastolic function only","Valve gradient","Cardiac output"], correctIndex: 0, rationale: "S' by TDI at the mitral annulus reflects longitudinal systolic function. Reduced S' (septal <6 cm/s or lateral <8 cm/s) indicates impaired systolic function.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "Tissue Doppler" },
  { id: "cs-058", stem: "Grade I diastolic dysfunction (impaired relaxation) shows:", options: ["E/A <0.8, DT >200 ms, and normal LA pressure markers","E/A >2.0","E/A 0.8-1.5 with elevated E/e'","Restrictive filling pattern"], correctIndex: 0, rationale: "Grade I: impaired relaxation with E/A <0.8, prolonged DT (>200 ms), normal LA size, and e' <7 cm/s (septal) or <10 cm/s (lateral). LA pressure is normal.", difficulty: 2, category: "Diastolic Function Assessment", topic: "Diastolic Grades" },
  { id: "cs-059", stem: "E/e' ratio greater than 14 suggests:", options: ["Elevated LV filling pressure","Normal filling pressure","Reduced cardiac output","Aortic stenosis"], correctIndex: 0, rationale: "E/e' is a key indicator of filling pressure. E/e' >14 = elevated filling pressure. E/e' <8 = normal. 8-14 = indeterminate (requires additional parameters).", difficulty: 2, category: "Diastolic Function Assessment", topic: "Filling Pressure" },
  { id: "cs-060", stem: "The lateral e' velocity is normally:", options: ["≥10 cm/s","<3 cm/s","≥20 cm/s","Not measurable"], correctIndex: 0, rationale: "Normal lateral e' ≥10 cm/s. Normal septal e' ≥7 cm/s. Reduced e' indicates impaired myocardial relaxation and is used to estimate filling pressures (E/e').", difficulty: 2, category: "Diastolic Function Assessment", topic: "Tissue Doppler" },
  { id: "cs-061", stem: "Pseudonormal filling pattern (Grade II diastolic dysfunction):", options: ["Has E/A ratio 0.8-2.0 with elevated E/e' >14, indicating elevated LA pressure masking impaired relaxation","Is a normal filling pattern","Shows E/A <0.8","Shows E/A >3.0"], correctIndex: 0, rationale: "Pseudonormal: appears normal (E/A 0.8-2.0) but elevated E/e', enlarged LA, and abnormal pulmonary vein flow reveal elevated filling pressure. Valsalva may unmask it.", difficulty: 3, category: "Diastolic Function Assessment", topic: "Diastolic Grades" },
  { id: "cs-062", stem: "Restrictive filling pattern (Grade III diastolic dysfunction) shows:", options: ["E/A ≥2.0, DT <160 ms, elevated E/e' >14, dilated LA, and elevated PA pressure","E/A <0.8","Normal filling pattern","Only mild relaxation abnormality"], correctIndex: 0, rationale: "Grade III (restrictive): E/A ≥2.0, short DT (<160 ms), elevated E/e', LA dilation, possible elevated PASP. Irreversible (Grade IV) doesn't change with Valsalva.", difficulty: 3, category: "Diastolic Function Assessment", topic: "Diastolic Grades" },
  { id: "cs-063", stem: "LA volume index is used in diastolic function assessment because:", options: ["LA volume reflects chronic filling pressure elevation — normal LAVI <34 mL/m²","It measures LA contractility","It determines heart rate","It assesses valve function"], correctIndex: 0, rationale: "LAVI >34 mL/m² indicates chronic LA pressure elevation. It serves as a 'chronicle' of filling pressures over time, similar to HbA1c reflecting average glucose.", difficulty: 2, category: "Diastolic Function Assessment", topic: "LA Assessment" },
  { id: "cs-064", stem: "Pulmonary vein flow pattern in normal subjects shows:", options: ["Systolic dominance (S > D) with a small a-wave reversal","Diastolic dominance","Only systolic flow","No flow detectable"], correctIndex: 0, rationale: "Normal PV flow: systolic (S) forward flow > diastolic (D) forward flow, with small a-wave reversal (<35 cm/s, duration < mitral A duration). S < D suggests elevated LA pressure.", difficulty: 2, category: "Diastolic Function Assessment", topic: "Venous Flow" },
  { id: "cs-065", stem: "The Ar-A duration is used to:", options: ["Estimate LV end-diastolic pressure — Ar-A duration >30 ms suggests elevated LVEDP","Measure aortic valve area","Assess RV function","Calculate cardiac output"], correctIndex: 0, rationale: "Ar = pulmonary vein a-wave reversal duration. A = mitral A-wave duration. Ar-A >30 ms suggests elevated LVEDP. This is useful in pseudonormal filling patterns.", difficulty: 3, category: "Diastolic Function Assessment", topic: "Advanced Diastolic" },
  { id: "cs-066", stem: "An atrial septal defect (ASD) allows blood flow between:", options: ["The right atrium and left atrium","The right ventricle and left ventricle","The aorta and pulmonary artery","The RV and RA"], correctIndex: 0, rationale: "ASD: abnormal communication between the RA and LA. Most common type: secundum ASD (fossa ovalis). Others: primum (associated with AV canal defect), sinus venosus, coronary sinus.", difficulty: 1, category: "Congenital Heart Disease", topic: "ASD" },
  { id: "cs-067", stem: "A ventricular septal defect (VSD) causes:", options: ["Left-to-right shunt with increased pulmonary blood flow","Right-to-left shunt","No hemodynamic effect","Decreased pulmonary blood flow"], correctIndex: 0, rationale: "VSD allows blood to shunt from the higher-pressure LV to the lower-pressure RV (left-to-right shunt). This increases pulmonary blood flow and may cause volume overload of the LA and LV.", difficulty: 2, category: "Congenital Heart Disease", topic: "VSD" },
  { id: "cs-068", stem: "Patent ductus arteriosus (PDA) connects:", options: ["The descending aorta to the pulmonary artery","The aorta to the SVC","The RA to the LA","The LV to the RV"], correctIndex: 0, rationale: "PDA: persistent communication between the descending aorta (just distal to the left subclavian) and the main pulmonary artery. Normally closes within days after birth.", difficulty: 1, category: "Congenital Heart Disease", topic: "PDA" },
  { id: "cs-069", stem: "Tetralogy of Fallot consists of:", options: ["VSD, overriding aorta, RV outflow tract obstruction, and RV hypertrophy","ASD, VSD, PDA, and aortic coarctation","Single ventricle and transposition","Ebstein anomaly and ASD"], correctIndex: 0, rationale: "TOF: (1) large VSD, (2) overriding aorta, (3) RVOT obstruction (subvalvular, valvular, or supravalvular), (4) RVH. Most common cyanotic CHD presenting after the neonatal period.", difficulty: 2, category: "Congenital Heart Disease", topic: "Tetralogy of Fallot" },
  { id: "cs-070", stem: "Ebstein anomaly involves:", options: ["Apical displacement of the septal and posterior tricuspid valve leaflets into the RV","Displacement of the mitral valve","Displacement of the aortic valve","Normal valve position"], correctIndex: 0, rationale: "Ebstein anomaly: the septal and posterior TV leaflets are displaced ≥8 mm/m² apically into the RV, creating an 'atrialized' portion of the RV above the displaced leaflets.", difficulty: 2, category: "Congenital Heart Disease", topic: "Ebstein Anomaly" },
  { id: "cs-071", stem: "Coarctation of the aorta is typically located:", options: ["Distal to the left subclavian artery at the aortic isthmus near the ligamentum arteriosum","At the aortic root","In the abdominal aorta","At the aortic arch proximal to the innominate artery"], correctIndex: 0, rationale: "Coarctation: discrete narrowing of the aorta, usually just distal to the left subclavian artery origin at the isthmus. Doppler shows increased velocity with diastolic 'sawtooth' pattern.", difficulty: 2, category: "Congenital Heart Disease", topic: "Coarctation" },
  { id: "cs-072", stem: "Qp/Qs ratio estimates:", options: ["The ratio of pulmonary to systemic blood flow — used to assess shunt significance","Heart rate","Blood pressure","Valve area"], correctIndex: 0, rationale: "Qp/Qs = RVOT SV / LVOT SV. Ratio >1.5:1 suggests a hemodynamically significant left-to-right shunt warranting intervention. Measured by Doppler at RVOT and LVOT.", difficulty: 3, category: "Congenital Heart Disease", topic: "Shunt Assessment" },
  { id: "cs-073", stem: "Transposition of the great arteries on echo shows:", options: ["The aorta arising from the RV and the pulmonary artery from the LV — parallel great arteries","Normal great artery connections","Only a single great artery","Great arteries arising from the same ventricle"], correctIndex: 0, rationale: "D-TGA: the aorta arises from the RV and PA from the LV. Echo shows parallel (not crossing) great arteries. Incompatible with life without mixing (ASD, VSD, or PDA).", difficulty: 3, category: "Congenital Heart Disease", topic: "TGA" },
  { id: "cs-074", stem: "The bubble study (agitated saline contrast) is used to detect:", options: ["Right-to-left shunt (ASD, PFO) — bubbles crossing from RA to LA within 3-5 cardiac cycles","LV thrombus","Pericardial effusion","Aortic dissection"], correctIndex: 0, rationale: "Agitated saline: microbubbles injected IV appear in the RA. Crossing to LA within 3-5 cycles suggests intracardiac shunt (PFO/ASD). Delayed appearance (>5 cycles) suggests pulmonary AVM.", difficulty: 2, category: "Congenital Heart Disease", topic: "Shunt Detection" },
  { id: "cs-075", stem: "The primary purpose of stress echocardiography is:", options: ["Detecting inducible myocardial ischemia by assessing wall motion at rest and during stress","Measuring resting valve function","Assessing pericardial disease","Evaluating congenital defects"], correctIndex: 0, rationale: "Stress echo detects ischemia by comparing LV wall motion at rest vs. stress. New or worsening RWMAs indicate ischemia. It also assesses hemodynamic significance of valvular disease.", difficulty: 1, category: "Stress Echocardiography", topic: "Stress Echo Principles" },
  { id: "cs-076", stem: "During dobutamine stress echo, the infusion protocol typically starts at:", options: ["5-10 mcg/kg/min and increases to 40 mcg/kg/min with atropine if needed","100 mcg/kg/min","0.1 mcg/kg/min","50 mg bolus"], correctIndex: 0, rationale: "DSE protocol: start at 5 mcg/kg/min, increase every 3 min (10→20→30→40). Atropine 0.25-1.0 mg added if target HR not reached. Monitor for ischemia at each stage.", difficulty: 2, category: "Stress Echocardiography", topic: "DSE Protocol" },
  { id: "cs-077", stem: "A biphasic response during dobutamine stress echo (improvement at low dose, worsening at high dose) suggests:", options: ["Viable myocardium with inducible ischemia — recoverable with revascularization","Fixed scar without viability","Normal response","Artifact"], correctIndex: 0, rationale: "Biphasic response: augmentation at low-dose dobutamine (5-10 mcg/kg/min = viable myocardium) followed by deterioration at peak dose (ischemia). This identifies hibernating myocardium.", difficulty: 3, category: "Stress Echocardiography", topic: "Viability Assessment" },
  { id: "cs-078", stem: "Target heart rate for stress echo is:", options: ["≥85% of age-predicted maximum heart rate (220 - age)","50% of max HR","100% of max HR","Any heart rate above resting"], correctIndex: 0, rationale: "Target HR: ≥85% × (220 - age). Submaximal test has reduced sensitivity. If exercise is used, symptoms/ECG changes may also be endpoints.", difficulty: 2, category: "Stress Echocardiography", topic: "Stress Endpoints" },
  { id: "cs-079", stem: "Which wall motion abnormality pattern corresponds to LAD territory?", options: ["Anterior wall, anteroseptal wall, and apex","Inferior and posterior walls","Lateral wall only","RV free wall"], correctIndex: 0, rationale: "LAD territory: anterior wall, anterior septum, and apex. RCA: inferior wall, inferior septum, RV. LCx: lateral and posterior walls.", difficulty: 2, category: "Stress Echocardiography", topic: "Coronary Territories" },
  { id: "cs-080", stem: "Exercise stress echo is preferred over dobutamine stress echo when:", options: ["The patient can exercise adequately — exercise provides more physiologic stress and prognostic data","The patient cannot exercise","The patient is on beta-blockers that cannot be stopped","The patient has severe aortic stenosis"], correctIndex: 0, rationale: "Exercise is the preferred stress modality when patients can achieve adequate workload. It provides additional prognostic information from exercise capacity, symptoms, and hemodynamic response.", difficulty: 2, category: "Stress Echocardiography", topic: "Stress Modalities" },
  { id: "cs-081", stem: "Indications to stop a dobutamine stress echo include:", options: ["New severe wall motion abnormality, significant arrhythmia, severe hypertension (>220 systolic), or intolerable symptoms","Reaching 50% of target HR","Mild increase in heart rate","Mild patient anxiety"], correctIndex: 0, rationale: "Stop criteria: new/worsening RWMA in ≥2 segments, complex arrhythmia, SBP >220 or drop >20 mmHg, severe symptoms, ST elevation, or reaching target HR.", difficulty: 2, category: "Stress Echocardiography", topic: "Safety" },
  { id: "cs-082", stem: "A pericardial effusion on echo appears as:", options: ["An echo-free space between the visceral and parietal pericardium","Increased myocardial thickness","A mass on the aortic valve","Calcified pericardium"], correctIndex: 0, rationale: "Pericardial effusion: anechoic space between the pericardial layers. Small: <10 mm in diastole (posterior only). Moderate: 10-20 mm. Large: >20 mm (circumferential).", difficulty: 1, category: "Pericardial Disease & Cardiomyopathies", topic: "Pericardial Effusion" },
  { id: "cs-083", stem: "Cardiac tamponade echo findings include:", options: ["RA systolic collapse, RV diastolic collapse, respirophasic changes in mitral/tricuspid inflow, and IVC plethora","Only a large pericardial effusion","Normal chamber sizes","Only RA dilation"], correctIndex: 0, rationale: "Tamponade: (1) RV diastolic collapse (specific), (2) RA systolic collapse/inversion (sensitive), (3) >25% respirophasic variation in mitral inflow, (4) plethoric IVC, (5) swinging heart.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Tamponade" },
  { id: "cs-084", stem: "Dilated cardiomyopathy (DCM) on echo shows:", options: ["LV dilation with reduced systolic function, thin walls, and often secondary MR and TR","Thick walls with small cavity","Normal LV size with diastolic dysfunction only","RV dilation with normal LV"], correctIndex: 0, rationale: "DCM: dilated LV (and often RV), thin walls, globally reduced EF, secondary MR/TR, possible intracardiac thrombus, and biatrial enlargement.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Dilated CMP" },
  { id: "cs-085", stem: "Hypertrophic cardiomyopathy (HCM) typically shows:", options: ["Asymmetric septal hypertrophy (≥15 mm), SAM of the mitral valve, and dynamic LVOT obstruction","Dilated thin-walled ventricle","Normal wall thickness","Pericardial effusion"], correctIndex: 0, rationale: "HCM: asymmetric hypertrophy (usually septal), systolic anterior motion (SAM) of the MV causing LVOT obstruction, diastolic dysfunction, and possible mitral regurgitation.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Hypertrophic CMP" },
  { id: "cs-086", stem: "Systolic anterior motion (SAM) of the mitral valve in HCM causes:", options: ["Dynamic LVOT obstruction that increases with decreased preload, decreased afterload, and increased contractility","Aortic regurgitation","Tricuspid stenosis","Pericardial effusion"], correctIndex: 0, rationale: "SAM: the MV anterior leaflet is drawn into the LVOT during systole (Venturi effect), causing obstruction. Provocative maneuvers: Valsalva, standing, exercise increase the gradient.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "LVOT Obstruction" },
  { id: "cs-087", stem: "Cardiac amyloidosis on echo classically shows:", options: ["Biventricular wall thickening with a 'sparkling' or 'ground glass' myocardial texture, biatrial enlargement, and diastolic dysfunction","Thin walls with dilated chambers","Normal echo findings","Only pericardial effusion"], correctIndex: 0, rationale: "Amyloid: concentric LV thickening, 'sparkling' granular echotexture (less reliable with harmonic imaging), biatrial enlargement, thickened valves, small pericardial effusion, restrictive filling.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Infiltrative CMP" },
  { id: "cs-088", stem: "Constrictive pericarditis on echo shows:", options: ["Pericardial thickening/calcification, septal bounce, respirophasic septal shift, and preserved/enhanced medial e' velocity","Large pericardial effusion","Dilated LV","Normal pericardium"], correctIndex: 0, rationale: "Constriction: thickened pericardium, diastolic septal bounce, >25% respirophasic changes in mitral/tricuspid inflow, enhanced medial e' velocity (annulus paradoxus), and plethoric IVC.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Constriction" },
  { id: "cs-089", stem: "Takotsubo (stress) cardiomyopathy on echo shows:", options: ["Apical ballooning with basal hyperkinesis — wall motion pattern not matching a single coronary territory","Global hypokinesis","Only apical hypertrophy","Normal wall motion"], correctIndex: 0, rationale: "Takotsubo: transient apical akinesis/dyskinesis with basal hyperkinesis (apical ballooning). The pattern crosses coronary territories. Often triggered by emotional/physical stress. Usually reversible.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Stress CMP" },
  { id: "cs-090", stem: "LV noncompaction on echo shows:", options: ["Prominent trabeculations with deep intertrabecular recesses in the LV, with NC/C ratio >2.3 at end-systole","Smooth, thin LV walls","Only RV involvement","Pericardial thickening"], correctIndex: 0, rationale: "LV noncompaction: spongy myocardium with prominent trabeculations and deep recesses communicating with the LV cavity. NC/C ratio >2.3 (Jenni criteria). Risk of HF, embolism, arrhythmia.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "LV Noncompaction" },
  { id: "cs-091", stem: "TEE provides better visualization than TTE for:", options: ["Posterior structures (LA, mitral valve, LAA, interatrial septum, thoracic aorta)","Anterior structures","The liver","The kidneys"], correctIndex: 0, rationale: "TEE: esophageal probe proximity to the heart improves visualization of posterior structures. Superior for MV pathology, LAA thrombus, ASD, endocarditis vegetations, and aortic pathology.", difficulty: 1, category: "TEE & Advanced Techniques", topic: "TEE Indications" },
  { id: "cs-092", stem: "The left atrial appendage (LAA) is best evaluated by:", options: ["TEE due to its posterior location and the need to detect small thrombi","TTE parasternal view","Subcostal view","Suprasternal view"], correctIndex: 0, rationale: "The LAA is a frequent site of thrombus in atrial fibrillation. TEE provides excellent resolution for detecting LAA thrombus, smoke, and sludge. Required before cardioversion.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "LAA Assessment" },
  { id: "cs-093", stem: "3D echocardiography is most useful for:", options: ["En-face visualization of the mitral valve, accurate LV volumes, and guidance during structural interventions","Replacing all 2D echo","Only research purposes","Only pediatric patients"], correctIndex: 0, rationale: "3D echo provides en-face (surgical) view of the MV, more accurate LV volumes than 2D, and real-time guidance for structural procedures (TAVI, MitraClip, ASD closure).", difficulty: 2, category: "TEE & Advanced Techniques", topic: "3D Echo" },
  { id: "cs-094", stem: "Intracardiac echocardiography (ICE) is used during:", options: ["Structural heart interventions (ASD/PFO closure, TAVI, ablation procedures) for real-time guidance","Routine outpatient echo","Exercise stress testing","Fetal echocardiography"], correctIndex: 0, rationale: "ICE: catheter-mounted transducer in the RA/RV provides real-time imaging during interventions. No general anesthesia needed (unlike TEE). Used for septal defect closure, ablation, and TAVI.", difficulty: 3, category: "TEE & Advanced Techniques", topic: "ICE" },
  { id: "cs-095", stem: "TEE probe insertion is contraindicated in:", options: ["Esophageal stricture, perforation, diverticulum, recent esophageal surgery, or active GI bleeding","All patients with heart failure","Patients with arrhythmias","Patients over age 80"], correctIndex: 0, rationale: "Absolute contraindications: esophageal obstruction/stricture, perforation, tumor, recent surgery, active UGI bleeding. Relative: cervical spine instability, severe coagulopathy.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "TEE Safety" },
  { id: "cs-096", stem: "Contrast echocardiography uses agitated saline or commercially produced microbubbles for:", options: ["LV opacification, endocardial border detection, shunt detection, and myocardial perfusion assessment","Replacing Doppler assessment","Measuring valve gradients","Assessing pericardial disease"], correctIndex: 0, rationale: "Echo contrast: agitated saline detects right-to-left shunts. Commercial microbubbles opacify LV for endocardial border definition, wall motion assessment, and myocardial perfusion imaging.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Contrast Echo" },
  { id: "cs-097", stem: "The right coronary artery (RCA) supplies:", options: ["The inferior wall, posterior wall, RV, and SA/AV nodes in most patients","The anterior wall","The lateral wall only","The apex only"], correctIndex: 0, rationale: "RCA supplies inferior wall, posterior descending artery (in right-dominant ~85%), RV, SA node (55%), and AV node (90%). RCA occlusion causes inferior MI.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Coronary Anatomy" },
  { id: "cs-098", stem: "The left circumflex artery (LCx) supplies:", options: ["The lateral and posterior walls of the left ventricle","The anterior septum","The RV","The aortic root"], correctIndex: 0, rationale: "LCx courses in the left AV groove, supplying the lateral and posterolateral walls. In left-dominant systems (~10%), it also gives rise to the posterior descending artery.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Coronary Anatomy" },
  { id: "cs-099", stem: "The fossa ovalis is located:", options: ["In the interatrial septum — the site of the foramen ovale","In the interventricular septum","In the aortic root","In the RV apex"], correctIndex: 0, rationale: "The fossa ovalis is a thin area in the interatrial septum representing the closed foramen ovale. It is the most common site for ASD (secundum type) and PFO.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Septal Anatomy" },
  { id: "cs-100", stem: "The papillary muscles of the left ventricle are:", options: ["Anterolateral and posteromedial, attached to mitral valve leaflets via chordae tendineae","Only one papillary muscle","Three papillary muscles","Located in the right ventricle"], correctIndex: 0, rationale: "Two LV papillary muscles: anterolateral (dual blood supply from LAD/LCx) and posteromedial (single supply, usually RCA or LCx). PM rupture is more common after inferior MI.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "LV Structure" },
  { id: "cs-101", stem: "The crux of the heart is the intersection of:", options: ["The posterior atrioventricular groove and the posterior interventricular groove","The anterior AV and anterior IV grooves","The aorta and PA","The SVC and IVC"], correctIndex: 0, rationale: "The crux is where the posterior AV groove, posterior IV groove, and interatrial septum converge. The AV node is located at the crux, supplied by the dominant coronary artery.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Anatomy" },
  { id: "cs-102", stem: "The Thebesian valve guards the opening of:", options: ["The coronary sinus into the right atrium","The IVC into the RA","The SVC into the RA","The pulmonary veins into the LA"], correctIndex: 0, rationale: "The Thebesian valve is a small fold of endocardium covering the ostium of the coronary sinus. It may be prominent and mistaken for pathology on echo.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Normal Variants" },
  { id: "cs-103", stem: "Normal cardiac output in a resting adult is approximately:", options: ["4-8 L/min","1-2 L/min","15-20 L/min","0.5 L/min"], correctIndex: 0, rationale: "Normal CO: 4-8 L/min. Cardiac index (CO/BSA): 2.5-4.0 L/min/m². CO can increase 4-6 times during exercise in healthy individuals.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Physiology" },
  { id: "cs-104", stem: "The Frank-Starling mechanism states:", options: ["As ventricular preload increases, the force of contraction increases (up to a point)","Heart rate determines cardiac output exclusively","Blood pressure is constant regardless of volume","Afterload has no effect on stroke volume"], correctIndex: 0, rationale: "Frank-Starling: increased preload stretches myocardial fibers, increasing the force of contraction and stroke volume. This allows the heart to adapt to changing venous return.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Physiology" },
  { id: "cs-105", stem: "Isovolumic contraction time (IVCT) is the period when:", options: ["Both the mitral and aortic valves are closed, LV pressure is rising rapidly","The mitral valve is open and filling occurs","The aortic valve is open and ejection occurs","The heart is in diastole"], correctIndex: 0, rationale: "IVCT: from mitral valve closure to aortic valve opening. Both valves closed, LV pressure rises rapidly. Normal IVCT: 60-90 ms. Prolonged in systolic dysfunction.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Cycle" },
  { id: "cs-106", stem: "Isovolumic relaxation time (IVRT) is the period when:", options: ["Both valves are closed, LV pressure is falling after aortic valve closure before mitral valve opening","The mitral valve is open","The aortic valve is open","Both valves are open"], correctIndex: 0, rationale: "IVRT: from aortic valve closure to mitral valve opening. Normal: 70-90 ms. Prolonged IVRT (>90 ms) = impaired relaxation. Short IVRT (<60 ms) = elevated LA pressure.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Cardiac Cycle" },
  { id: "cs-107", stem: "The right ventricular outflow tract (RVOT) view is obtained from:", options: ["The PSAX at the aortic valve level, showing the RVOT and pulmonic valve","The apical 4-chamber view","The subcostal view","The suprasternal view"], correctIndex: 0, rationale: "RVOT is best seen in PSAX at AV level and from a modified high parasternal or subcostal view. Important for PV assessment, PS/PR evaluation, and RVOT measurements.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Specialized Views" },
  { id: "cs-108", stem: "The apical 4-chamber view specifically evaluates:", options: ["All four chambers, both AV valves, interatrial and interventricular septa, and apical wall segments","Only the aortic valve","Only the left heart","Only the pericardium"], correctIndex: 0, rationale: "A4C evaluates: LV/RV size/function, LA/RA size, MV/TV morphology and function, septal integrity, and apical/lateral/septal/inferior wall segments.", difficulty: 1, category: "Standard Echocardiography Views", topic: "View Applications" },
  { id: "cs-109", stem: "Off-axis views may be necessary when:", options: ["Standard views are limited by body habitus, lung disease, or surgical changes","Never — only standard views should be used","The patient is young","The equipment is outdated"], correctIndex: 0, rationale: "Modified/off-axis views adapt to individual anatomy. Common modifications include higher/lower intercostal spaces, lateral decubitus positioning, and non-standard angulations.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Imaging Technique" },
  { id: "cs-110", stem: "Foreshortening of the LV in apical views occurs when:", options: ["The transducer is not positioned at the true apex, making the LV appear shorter and LVEF overestimated","The LV is truly small","The patient is tachycardic","The gain is too high"], correctIndex: 0, rationale: "Foreshortening: the LV appears shorter than its true length because the apex is cut off. This artifactually reduces volumes and overestimates LVEF. Optimize to get the longest LV cavity.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Quality Optimization" },
  { id: "cs-111", stem: "M-mode echocardiography has excellent:", options: ["Temporal resolution for measuring rapidly moving structures","Spatial resolution","Color flow detection","3D capabilities"], correctIndex: 0, rationale: "M-mode: single beam line plotted over time with very high temporal resolution (~1000 Hz). Ideal for timing events, measuring dimensions, and assessing valve/wall motion timing.", difficulty: 1, category: "Standard Echocardiography Views", topic: "M-Mode" },
  { id: "cs-112", stem: "The Doppler velocity index (DVI) for aortic valve assessment is:", options: ["The ratio of LVOT VTI to AV VTI — DVI <0.25 suggests severe aortic stenosis","AV VTI / LVOT VTI","Peak velocity ratio","Gradient ratio"], correctIndex: 0, rationale: "DVI = LVOT VTI / AV VTI (or velocities). Normal DVI >0.50. DVI <0.25 = severe AS. Advantage: independent of LVOT area measurement (avoids squaring errors).", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Aortic Stenosis" },
  { id: "cs-113", stem: "Mean gradient across a valve is determined by:", options: ["Tracing the CW Doppler envelope and averaging instantaneous gradients throughout the flow period","Only the peak velocity","Only the end-diastolic velocity","Heart rate multiplied by peak gradient"], correctIndex: 0, rationale: "Mean gradient: trace the CW Doppler envelope, the machine calculates the average of all instantaneous gradients. More representative of hemodynamic burden than peak gradient.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Gradient Measurement" },
  { id: "cs-114", stem: "Low-flow, low-gradient aortic stenosis is characterized by:", options: ["AVA ≤1.0 cm² but mean gradient <40 mmHg due to reduced LV systolic function","Normal AVA with high gradients","Moderate AS with normal EF","Mild AS with preserved EF"], correctIndex: 0, rationale: "Low-flow, low-gradient AS: reduced SV → reduced flow → lower transvalvular velocities/gradients despite severely stenotic valve. Dobutamine stress echo can differentiate true-severe from pseudo-severe.", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "Complex AS" },
  { id: "cs-115", stem: "The regurgitant fraction is calculated as:", options: ["(Regurgitant volume / Total stroke volume) × 100%","Peak velocity / mean velocity","Heart rate / stroke volume","Gradient / velocity"], correctIndex: 0, rationale: "RF = (RegVol / Total SV) × 100%. Total SV = forward SV + regurgitant volume. RF ≥50% indicates severe regurgitation for both MR and AR.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Regurgitation" },
  { id: "cs-116", stem: "Right ventricular systolic pressure (RVSP) equals:", options: ["PASP in the absence of pulmonic stenosis — estimated from TR velocity and RAP","LV systolic pressure","Aortic diastolic pressure","LA pressure"], correctIndex: 0, rationale: "RVSP = PASP when there is no pulmonic stenosis. RVSP = 4(TR Vmax)² + RAP. If PS is present, RVSP = PASP + PS gradient.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Right Heart" },
  { id: "cs-117", stem: "Transmitral flow velocity is measured by:", options: ["Pulsed wave Doppler at the mitral valve leaflet tips in the apical 4-chamber view","CW Doppler through the aorta","PW Doppler in the LVOT","M-mode of the mitral valve"], correctIndex: 0, rationale: "Transmitral PW Doppler: sample volume at MV leaflet tips in A4C. Records E and A waves for diastolic function assessment. E = early filling, A = atrial contraction.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Diastolic Assessment" },
  { id: "cs-118", stem: "The E/A ratio reversal (E/A <1) with aging is:", options: ["A normal age-related finding due to impaired relaxation — common after age 60","Always pathological","A sign of severe heart failure","Not related to aging"], correctIndex: 0, rationale: "Normal aging: impaired relaxation with E/A reversal (<1) is common after age 60. This is 'age-appropriate' Grade I diastolic dysfunction, often without symptoms.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Normal Aging" },
  { id: "cs-119", stem: "Tissue Doppler imaging (TDI) measures:", options: ["Myocardial velocities at the mitral and tricuspid annuli — e', a', and s' velocities","Blood flow velocities only","Valve gradients","Chamber volumes"], correctIndex: 0, rationale: "TDI uses low-frequency, high-amplitude signals from myocardial motion. E' (early diastolic), a' (late diastolic), and s' (systolic) velocities at the annuli assess myocardial function.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Tissue Doppler" },
  { id: "cs-120", stem: "The dimensionless index (DVI) for mitral valve uses:", options: ["The ratio of mitral E-wave VTI to mitral A-wave VTI is NOT the same as the aortic DVI — for prosthetic MV: MV VTI / LVOT VTI","Only peak velocities","Only mean gradients","Only valve areas"], correctIndex: 0, rationale: "For prosthetic MV assessment, DVI = MV VTI / LVOT VTI. Values vary by prosthesis type. Elevated DVI suggests prosthetic MV stenosis or patient-prosthesis mismatch.", difficulty: 3, category: "Valvular Heart Disease", topic: "Prosthetic Valves" },
  { id: "cs-121", stem: "Bicuspid aortic valve is the most common congenital cardiac anomaly with prevalence of:", options: ["1-2% of the population","10% of the population","0.01% of the population","50% of the population"], correctIndex: 0, rationale: "BAV occurs in 1-2% of the population, more common in males (3:1). Associated with aortopathy (ascending aortic dilation/aneurysm), AS, and AR.", difficulty: 2, category: "Valvular Heart Disease", topic: "Congenital Valve" },
  { id: "cs-122", stem: "Libman-Sacks endocarditis is associated with:", options: ["Systemic lupus erythematosus (SLE) and antiphospholipid syndrome","Streptococcal infection","Staphylococcal bacteremia","Rheumatic fever"], correctIndex: 0, rationale: "Libman-Sacks: non-bacterial thrombotic endocarditis in SLE/APS. Sterile vegetations typically on the ventricular side of the mitral valve. Usually not hemodynamically significant.", difficulty: 3, category: "Valvular Heart Disease", topic: "Non-Infectious Endocarditis" },
  { id: "cs-123", stem: "Carcinoid heart disease primarily affects:", options: ["The right-sided heart valves (tricuspid and pulmonic) causing regurgitation and stenosis","The left-sided valves only","No cardiac involvement","Only the aortic valve"], correctIndex: 0, rationale: "Carcinoid: serotonin-mediated fibrosis of right heart valves (TR and PR most common). Right-sided because the lung metabolizes serotonin before it reaches the left heart.", difficulty: 3, category: "Valvular Heart Disease", topic: "Valve Disease" },
  { id: "cs-124", stem: "Rheumatic mitral stenosis on echo characteristically shows:", options: ["Commissural fusion, hockey-stick anterior leaflet, restricted posterior leaflet, and chordal shortening/fusion","Normal valve mobility","Only calcification","Only annular dilation"], correctIndex: 0, rationale: "Rheumatic MS: commissural fusion, restricted leaflet opening, hockey-stick (elbow) deformity of the AML, tethered PML, chordal thickening/shortening, and possible LA thrombus.", difficulty: 2, category: "Valvular Heart Disease", topic: "Mitral Stenosis" },
  { id: "cs-125", stem: "Aortic root dilation is concerning when the diameter exceeds:", options: ["4.0-4.5 cm depending on body size (or >2.1 cm/m² indexed)","2.0 cm","1.0 cm","6.0 cm in all patients"], correctIndex: 0, rationale: "Aortic root dilation: >4.0 cm is dilated. Surgery considered at >5.0-5.5 cm (or >4.5 cm with BAV, Marfan, or rapid growth). Measured at sinuses of Valsalva.", difficulty: 2, category: "Valvular Heart Disease", topic: "Aortic Disease" },
  { id: "cs-126", stem: "Papillary muscle rupture after MI causes:", options: ["Acute severe mitral regurgitation with hemodynamic compromise","Aortic stenosis","Pulmonic regurgitation","Normal valve function"], correctIndex: 0, rationale: "Papillary muscle rupture: complication of MI (usually inferior, posteromedial PM). Causes acute severe MR → pulmonary edema → cardiogenic shock. Surgical emergency.", difficulty: 3, category: "Valvular Heart Disease", topic: "Acute MR" },
  { id: "cs-127", stem: "The pressure half-time (PHT) for mitral stenosis:", options: ["PHT >220 ms with MVA = 220/PHT — longer PHT = more severe stenosis","Is not used for MS assessment","Only applies to aortic regurgitation","Has no clinical significance"], correctIndex: 0, rationale: "MS PHT: time for peak gradient to decrease to half. MVA = 220/PHT. Severe MS: PHT >220 ms (MVA <1.0). Moderate: PHT 150-220 ms (MVA 1.0-1.5). Mild: PHT <150 ms.", difficulty: 2, category: "Valvular Heart Disease", topic: "MS Assessment" },
  { id: "cs-128", stem: "A paravalvular leak after valve replacement:", options: ["Is a regurgitant jet originating outside the sewing ring through the annulus","Is a jet through the valve mechanism","Is always clinically insignificant","Cannot be detected by echo"], correctIndex: 0, rationale: "Paravalvular leak: regurgitation around (not through) the prosthetic valve due to incomplete sealing at the annulus. May require intervention if hemodynamically significant or causing hemolysis.", difficulty: 2, category: "Valvular Heart Disease", topic: "Prosthetic Complications" },
  { id: "cs-129", stem: "Aortic valve sclerosis differs from stenosis in that:", options: ["Sclerosis has thickening/calcification without flow obstruction (peak velocity <2.0 m/s)","Sclerosis is more severe than stenosis","They are the same condition","Sclerosis requires surgery"], correctIndex: 0, rationale: "Aortic sclerosis: valve thickening/calcification WITHOUT significant obstruction (peak velocity <2.0 m/s). Present in ~25% of adults >65. Associated with increased cardiovascular risk.", difficulty: 2, category: "Valvular Heart Disease", topic: "Aortic Valve" },
  { id: "cs-130", stem: "LV mass is increased (LV hypertrophy) when:", options: ["LV mass index exceeds 95 g/m² in women or 115 g/m² in men","LV wall is <6 mm","LV cavity is enlarged","EF is normal"], correctIndex: 0, rationale: "LVH: LV mass index >95 g/m² (women) or >115 g/m² (men). Calculated from LV dimensions (cube formula) or 2D-derived. Patterns: concentric, eccentric, concentric remodeling.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "LV Mass" },
  { id: "cs-131", stem: "Concentric LV hypertrophy is characterized by:", options: ["Increased wall thickness with normal or small LV cavity — RWT >0.42 and increased LV mass","Thin walls with dilated cavity","Normal wall thickness","Only septal hypertrophy"], correctIndex: 0, rationale: "Concentric LVH: thick walls (>12 mm), normal/small cavity, RWT >0.42. Causes: hypertension, aortic stenosis, HCM, infiltrative diseases. Eccentric LVH has normal RWT with dilated LV.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "LV Geometry" },
  { id: "cs-132", stem: "3D echocardiography for LV volumes is more accurate than 2D because:", options: ["It avoids geometric assumptions and foreshortening, measuring the true 3D endocardial surface","It uses higher frequency","It has better temporal resolution","It is faster"], correctIndex: 0, rationale: "3D LVEF avoids the geometric assumptions of 2D (Simpson's) and is less affected by foreshortening. It provides more accurate and reproducible LV volumes and LVEF.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "3D Assessment" },
  { id: "cs-133", stem: "Left ventricular thrombus is most commonly found:", options: ["At the LV apex in the setting of apical akinesis or aneurysm after anterior MI","In the LVOT","At the mitral annulus","In the RV"], correctIndex: 0, rationale: "LV thrombus: most common at the apex with anterior MI causing apical akinesis/dyskinesis. Also in DCM. Echo contrast or CMR improves detection sensitivity.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "LV Thrombus" },
  { id: "cs-134", stem: "RV fractional area change (FAC) is:", options: ["The percentage change in RV area from diastole to systole — normal ≥35%","LV area change","LA area change","Aortic root area change"], correctIndex: 0, rationale: "RV FAC = (RV end-diastolic area - RV end-systolic area) / RV end-diastolic area × 100%. Normal ≥35%. Measured in the focused RV A4C view.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "RV Function" },
  { id: "cs-135", stem: "The E/e' ratio is considered the best noninvasive estimate of:", options: ["LV filling pressure (elevated E/e' correlates with elevated PCWP)","Cardiac output","Valve area","RV systolic pressure"], correctIndex: 0, rationale: "E/e' correlates with pulmonary capillary wedge pressure (PCWP). Average E/e' (septal + lateral / 2): >14 = elevated filling pressure, <8 = normal, 8-14 = indeterminate.", difficulty: 2, category: "Diastolic Function Assessment", topic: "Filling Pressure" },
  { id: "cs-136", stem: "TR velocity >2.8 m/s in diastolic function assessment suggests:", options: ["Elevated pulmonary artery pressure, supporting elevated filling pressures","Normal pulmonary pressure","Low pulmonary pressure","Pulmonic stenosis"], correctIndex: 0, rationale: "TR velocity >2.8 m/s estimates PASP >35 mmHg (with normal RAP). In diastolic assessment, elevated PASP supports the diagnosis of elevated LV filling pressures.", difficulty: 2, category: "Diastolic Function Assessment", topic: "Supplementary Data" },
  { id: "cs-137", stem: "The mitral L velocity on Doppler:", options: ["Represents mid-diastolic flow seen in constrictive pericarditis, high filling pressures, or Grade III/IV diastolic dysfunction","Is a normal finding","Represents systolic flow","Is an artifact"], correctIndex: 0, rationale: "The L wave: mid-diastolic mitral flow between E and A waves. Indicates continued filling during diastasis, seen with elevated LA pressure, constrictive pericarditis, or high-output states.", difficulty: 3, category: "Diastolic Function Assessment", topic: "Advanced Patterns" },
  { id: "cs-138", stem: "A patent foramen ovale (PFO) is detected by:", options: ["Bubble study showing contrast crossing from RA to LA within 3-5 cardiac cycles, especially with provocative maneuvers","CW Doppler of the aorta","M-mode of the LV","Color Doppler of the pulmonary veins"], correctIndex: 0, rationale: "PFO detection: inject agitated saline IV, observe for bubbles crossing to LA within 3-5 cycles (especially with Valsalva release or cough). PFO present in ~25% of population.", difficulty: 2, category: "Congenital Heart Disease", topic: "PFO" },
  { id: "cs-139", stem: "Eisenmenger syndrome occurs when:", options: ["A long-standing left-to-right shunt causes irreversible pulmonary hypertension leading to shunt reversal (right-to-left)","There is mild PR","A small ASD closes spontaneously","Normal pulmonary pressures develop"], correctIndex: 0, rationale: "Eisenmenger: chronically elevated pulmonary blood flow from L→R shunt causes irreversible pulmonary vascular disease. When PVR exceeds SVR, the shunt reverses (R→L) causing cyanosis.", difficulty: 3, category: "Congenital Heart Disease", topic: "Shunt Complications" },
  { id: "cs-140", stem: "An atrioventricular canal defect (AVCD) includes:", options: ["Primum ASD, inlet VSD, and a common AV valve — associated with Down syndrome","Only a secundum ASD","Only a muscular VSD","Only a PDA"], correctIndex: 0, rationale: "Complete AVCD: primum ASD + inlet VSD + single common AV valve. Strong association with trisomy 21 (Down syndrome). Partial AVCD has only the primum ASD component.", difficulty: 2, category: "Congenital Heart Disease", topic: "AV Canal Defect" },
  { id: "cs-141", stem: "Aortic coarctation on echo may show:", options: ["Narrowing of the aortic isthmus with diastolic runoff pattern on Doppler and LV hypertrophy","Normal aortic arch","Aortic root aneurysm only","Pulmonary artery dilation"], correctIndex: 0, rationale: "Coarctation: discrete isthmic narrowing. Suprasternal Doppler shows increased velocity at the narrowing with 'sawtooth' diastolic tail. Associated with BAV, VSD, and Berry aneurysms.", difficulty: 2, category: "Congenital Heart Disease", topic: "Coarctation" },
  { id: "cs-142", stem: "Cor triatriatum sinister is:", options: ["A membrane dividing the LA into two chambers, potentially obstructing pulmonary venous return","A membrane in the RA","A three-chambered heart","An extra ventricle"], correctIndex: 0, rationale: "Cor triatriatum: fibromuscular membrane in the LA creating a proximal chamber (receiving PVs) and a distal chamber (containing LAA and MV). May mimic mitral stenosis hemodynamically.", difficulty: 3, category: "Congenital Heart Disease", topic: "Rare Anomalies" },
  { id: "cs-143", stem: "Persistent left SVC draining into the coronary sinus:", options: ["Causes coronary sinus dilation on echo and is usually hemodynamically insignificant","Causes severe heart failure","Requires immediate surgery","Is never seen on echo"], correctIndex: 0, rationale: "Persistent left SVC (PLSVC): most common thoracic venous anomaly. Drains into the coronary sinus, causing it to dilate. Usually benign but important to recognize before device implantation.", difficulty: 2, category: "Congenital Heart Disease", topic: "Venous Anomalies" },
  { id: "cs-144", stem: "Myocardial viability assessment with dobutamine echo:", options: ["Low-dose (5-10 mcg/kg/min) dobutamine can identify viable (hibernating) myocardium that improves with augmentation","Only high-dose dobutamine is used","Viability cannot be assessed by echo","Only exercise stress is useful"], correctIndex: 0, rationale: "Low-dose dobutamine stimulates chronically dysfunctional but viable myocardium. Improvement (augmentation) indicates recoverable contractile reserve with revascularization.", difficulty: 2, category: "Stress Echocardiography", topic: "Viability" },
  { id: "cs-145", stem: "False-positive stress echo results may occur with:", options: ["LBBB, RV pacing, or pre-existing wall motion abnormalities","Perfect test conditions","Normal resting echo","Adequate heart rate achievement"], correctIndex: 0, rationale: "LBBB causes paradoxical septal motion that can be mistaken for ischemia. Pre-existing WMAs make assessment of new abnormalities difficult. Consider alternative modalities.", difficulty: 2, category: "Stress Echocardiography", topic: "Limitations" },
  { id: "cs-146", stem: "Peak exercise images should be acquired within:", options: ["60-90 seconds after exercise to capture ischemia before it resolves","10 minutes after exercise","30 minutes after exercise","Before exercise begins"], correctIndex: 0, rationale: "Post-exercise images must be captured rapidly (<60-90 seconds) as wall motion abnormalities from ischemia may normalize quickly. Bicycle exercise allows imaging during peak exercise.", difficulty: 2, category: "Stress Echocardiography", topic: "Protocol" },
  { id: "cs-147", stem: "Dobutamine stress echo wall motion grading uses:", options: ["A 17-segment model comparing resting to stress wall motion — new/worsening hypokinesis = positive","Only 4 segments","Only the apex","Doppler velocities only"], correctIndex: 0, rationale: "The 17-segment model (AHA): each segment scored 1-5 at rest and stress. A positive test shows new or worsening wall motion (e.g., normal→hypokinetic or hypo→akinetic).", difficulty: 2, category: "Stress Echocardiography", topic: "Interpretation" },
  { id: "cs-148", stem: "Restrictive cardiomyopathy on echo shows:", options: ["Normal or small LV with diastolic dysfunction, biatrial enlargement, and preserved systolic function initially","Dilated LV with thin walls","Normal echo findings","Only pericardial effusion"], correctIndex: 0, rationale: "Restrictive CMP: normal/small LV size, normal/mild LVH, preserved EF (initially), biatrial enlargement, restrictive filling pattern. Causes: amyloid, sarcoid, hemochromatosis, fibrosis.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Restrictive CMP" },
  { id: "cs-149", stem: "Distinguishing constrictive pericarditis from restrictive cardiomyopathy:", options: ["Constriction shows septal bounce, annulus paradoxus (enhanced medial e'), and respirophasic changes; restriction shows reduced e' and no septal bounce","They are identical on echo","Only MRI can distinguish them","Only cardiac catheterization is useful"], correctIndex: 0, rationale: "Key differences: Constriction — septal bounce, enhanced medial e' (annulus paradoxus), E/e' may be lower. Restriction — reduced e', no septal bounce, higher E/e'. Both have restrictive filling.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Differentiation" },
  { id: "cs-150", stem: "Cardiac masses on echo may include:", options: ["Thrombus, vegetation, tumor (myxoma, papillary fibroelastoma, rhabdomyoma), and normal variants","Only thrombi","Only tumors","Only vegetations"], correctIndex: 0, rationale: "Echo detects various masses: thrombi (LA/LV), vegetations (valves), primary tumors (myxoma most common), metastatic tumors (more common than primary), and normal variants (Chiari network, Lambl excrescences).", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Cardiac Masses" },
  { id: "cs-151", stem: "Left atrial myxoma on echo typically appears as:", options: ["A pedunculated, mobile, heterogeneous mass attached to the interatrial septum at the fossa ovalis, prolapsing through the mitral valve","A fixed calcified mass on the aortic valve","A thrombus in the LAA","A pericardial mass"], correctIndex: 0, rationale: "LA myxoma: most common primary cardiac tumor. Pedunculated, gelatinous, attached to IAS near fossa ovalis. May prolapse through MV causing obstruction. Can embolize. Surgical excision required.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Cardiac Tumors" },
  { id: "cs-152", stem: "Papillary fibroelastoma on echo appears as:", options: ["A small (<1 cm), mobile, pedunculated mass on a valve surface, often on the aortic valve","A large fixed mass in the LA","A thrombus","A vegetation"], correctIndex: 0, rationale: "Fibroelastoma: small, round, mobile mass on a valve surface (most common on AV). Stippled border may create 'shimmer.' Embolic risk warrants surgical excision if on the left side.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Cardiac Tumors" },
  { id: "cs-153", stem: "Arrhythmogenic right ventricular cardiomyopathy (ARVC) shows:", options: ["RV dilation, wall thinning, focal RV aneurysms, fatty/fibrotic infiltration, and reduced RV function","Normal RV","LV dilation only","Pericardial effusion only"], correctIndex: 0, rationale: "ARVC: fibrofatty replacement of RV myocardium causing RV dilation, reduced function, and ventricular arrhythmias. Echo findings: RV dilation, focal wall thinning/aneurysms, reduced FAC.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "RV Cardiomyopathy" },
  { id: "cs-154", stem: "Löffler endocarditis on echo shows:", options: ["Apical obliteration by thrombus with preserved basal function, eosinophilic infiltration","Normal LV apex","Aortic root dilation","Normal valves"], correctIndex: 0, rationale: "Löffler (hypereosinophilic) endocarditis: eosinophilic infiltration causes endocardial fibrosis, apical thrombus formation, and cavity obliteration. AV valve regurgitation may develop.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Infiltrative" },
  { id: "cs-155", stem: "Right atrial mass differential includes:", options: ["Thrombus, myxoma, metastatic tumor, Chiari network, eustachian valve, crista terminalis, and pacemaker lead","Only thrombus","Only myxoma","Nothing — masses never occur in the RA"], correctIndex: 0, rationale: "RA masses: thrombus (in-transit or mural), myxoma, metastatic tumor (RCC, hepatocellular), lipomatous hypertrophy, normal structures (Chiari, eustachian, crista), and catheter/lead related.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Cardiac Masses" },
  { id: "cs-156", stem: "Mid-esophageal four-chamber view on TEE shows:", options: ["All four chambers, both AV valves, and interatrial/interventricular septa with excellent resolution","Only the aortic valve","The descending aorta","The stomach"], correctIndex: 0, rationale: "ME 4-chamber on TEE: excellent resolution of all four chambers, MV/TV, IAS (for PFO/ASD), and septa. Higher resolution than TTE due to esophageal proximity.", difficulty: 1, category: "TEE & Advanced Techniques", topic: "TEE Views" },
  { id: "cs-157", stem: "TEE is the gold standard for evaluating:", options: ["Mitral valve pathology, LAA thrombus, prosthetic valve endocarditis, and aortic dissection","Only LV systolic function","Only pericardial effusion","Only congenital heart disease"], correctIndex: 0, rationale: "TEE superiority: MV anatomy (surgical planning), LAA thrombus (pre-cardioversion), prosthetic valve assessment, native/prosthetic endocarditis, and thoracic aortic dissection.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "TEE Indications" },
  { id: "cs-158", stem: "During TEE-guided MitraClip procedure:", options: ["TEE provides real-time guidance for device positioning, grasping of leaflets, and assessment of residual MR","TEE is not used during the procedure","Only fluoroscopy is needed","TTE provides adequate imaging"], correctIndex: 0, rationale: "TEE is essential for MitraClip: guides transseptal puncture, device positioning, leaflet grasping, and assesses residual MR. 3D TEE enhances visualization of the mitral anatomy.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Interventional Guidance" },
  { id: "cs-159", stem: "Aortic dissection on TEE shows:", options: ["An intimal flap separating true and false lumens, with possible aortic regurgitation and pericardial effusion","Normal aorta","Only aortic stenosis","Mitral valve prolapse"], correctIndex: 0, rationale: "TEE for dissection: linear intimal flap dividing true (smaller, higher flow) and false (larger, possible thrombus) lumens. Type A involves ascending aorta. Pericardial effusion suggests rupture.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Aortic Disease" },
  { id: "cs-160", stem: "Strain imaging (speckle tracking) can detect:", options: ["Subclinical myocardial dysfunction before LVEF decreases, including chemotherapy cardiotoxicity and infiltrative diseases","Only valve disease","Only pericardial disease","Only congenital defects"], correctIndex: 0, rationale: "Strain imaging detects early myocardial dysfunction: GLS decrease precedes LVEF reduction in chemotherapy cardiotoxicity, cardiac amyloidosis (apical sparing pattern), and ischemic disease.", difficulty: 3, category: "TEE & Advanced Techniques", topic: "Advanced Imaging" },
  { id: "cs-161", stem: "The SVC enters the:", options: ["Right atrium at its superior aspect","Left atrium","Right ventricle","Left ventricle"], correctIndex: 0, rationale: "The SVC drains venous blood from the upper body into the superior RA. It is best visualized in subcostal and suprasternal views.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Venous Anatomy" },
  { id: "cs-162", stem: "The tricuspid valve has:", options: ["Three leaflets: anterior, septal, and posterior","Two leaflets","Four leaflets","One leaflet"], correctIndex: 0, rationale: "The TV has anterior (largest), septal, and posterior leaflets. The septal leaflet inserts slightly more apically than the MV (important for identifying AV discordance).", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Valve Anatomy" },
  { id: "cs-163", stem: "The left main coronary artery bifurcates into:", options: ["The LAD and left circumflex arteries","The RCA and LAD","The LAD and diagonal","The PDA and PLB"], correctIndex: 0, rationale: "The left main (LMCA) arises from the left aortic sinus and bifurcates into the LAD and LCx. In some patients, it trifurcates with a ramus intermedius.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Coronary Anatomy" },
  { id: "cs-164", stem: "Normal LV wall thickness at end-diastole is:", options: ["6-11 mm","1-3 mm","15-20 mm","25-30 mm"], correctIndex: 0, rationale: "Normal LV wall: 6-11 mm at end-diastole. LVH: ≥12 mm. Measured in PLAX at the tips of the mitral leaflets. Asymmetric if septal/free wall ratio >1.3.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "LV Dimensions" },
  { id: "cs-165", stem: "The pericardium consists of:", options: ["A fibrous outer layer and a serous inner layer (with visceral and parietal components)","Only a single layer","Three separate layers of muscle","No defined structure"], correctIndex: 0, rationale: "The pericardium has fibrous (outer) and serous (inner) layers. The serous layer has parietal and visceral (epicardium) components. Normal pericardial fluid: 15-50 mL.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Pericardial Anatomy" },
  { id: "cs-166", stem: "Normal LV internal diameter at end-diastole (LVIDd) is:", options: ["3.5-5.7 cm (gender and BSA dependent)","1.0-2.0 cm","7.0-8.0 cm","10 cm"], correctIndex: 0, rationale: "Normal LVIDd: 3.5-5.7 cm (varies by gender and body size). Indexed values are more accurate. LVIDd >5.7 cm suggests LV dilation.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "LV Dimensions" },
  { id: "cs-167", stem: "The aortic root includes:", options: ["The sinuses of Valsalva, aortic valve annulus, and sinotubular junction","Only the ascending aorta","Only the aortic arch","Only the descending aorta"], correctIndex: 0, rationale: "The aortic root encompasses the aortic annulus, aortic cusps, sinuses of Valsalva (right, left, non-coronary), and sinotubular junction. Measured in PLAX at end-diastole.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Aortic Anatomy" },
  { id: "cs-168", stem: "Normal LA diameter in the PLAX view should be less than:", options: ["4.0 cm (or LA volume index <34 mL/m²)","6.0 cm","1.0 cm","8.0 cm"], correctIndex: 0, rationale: "Normal LA diameter: <4.0 cm (AP in PLAX). LA volume index (biplane method) <34 mL/m² is more accurate. LA enlargement suggests chronic pressure/volume overload.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "LA Assessment" },
  { id: "cs-169", stem: "The parasternal short-axis sweep moves from:", options: ["Base (aortic valve level) through the mitral valve level to the apex (papillary muscle level and beyond)","Apex to base only","Only one level","Right to left"], correctIndex: 0, rationale: "PSAX sweep: AV level (Mercedes-Benz sign) → MV level (fish-mouth appearance) → papillary muscle level (symmetric contraction) → apical level. Each level assesses different coronary territories.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Technique" },
  { id: "cs-170", stem: "The right ventricular focused apical view:", options: ["Optimizes visualization of the RV by tilting the transducer laterally from the standard A4C","Is the same as A4C","Only shows the LV","Is obtained subcostally"], correctIndex: 0, rationale: "RV-focused A4C: maximize RV size in the sector. Used for RV measurements (basal diameter >4.2 cm = dilated), TAPSE, FAC, and RV free wall strain.", difficulty: 2, category: "Standard Echocardiography Views", topic: "RV Assessment" },
  { id: "cs-171", stem: "Image optimization in echocardiography includes:", options: ["Adjusting depth, gain, TGC, compression, focus, and patient positioning","Using only default settings","Never adjusting controls","Only changing the transducer"], correctIndex: 0, rationale: "Optimization: narrow sector width, appropriate depth, focal zones at structure of interest, TGC for uniform brightness, overall gain for tissue visualization, and harmonic imaging.", difficulty: 1, category: "Standard Echocardiography Views", topic: "Technique" },
  { id: "cs-172", stem: "The EROA (effective regurgitant orifice area) quantifies:", options: ["The cross-sectional area of the regurgitant orifice — a direct measure of regurgitation severity","The stenotic orifice area","The valve annulus area","The chamber area"], correctIndex: 0, rationale: "EROA is calculated by PISA method: EROA = (2π × r² × aliasing velocity) / peak regurgitant velocity. Severe MR: EROA ≥0.40 cm². Severe AR: EROA ≥0.30 cm².", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "PISA Method" },
  { id: "cs-173", stem: "The mitral inflow E/A ratio in atrial fibrillation:", options: ["Cannot be used because there is no organized atrial contraction (A wave)","Is always normal","Shows a large A wave","Is unaffected by rhythm"], correctIndex: 0, rationale: "In AF: no organized atrial contraction → absent A wave. E wave represents all diastolic filling. DT and E/e' are used for filling pressure assessment in AF.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Special Situations" },
  { id: "cs-174", stem: "Flow acceleration proximal to a stenosis suggests:", options: ["The velocity is increasing as blood approaches the narrowed orifice (convergence)","Normal laminar flow","Turbulence","Artifact"], correctIndex: 0, rationale: "Proximal flow acceleration/convergence: flow velocity increases as blood converges toward a stenotic or regurgitant orifice. This is the basis of the PISA method.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Flow Dynamics" },
  { id: "cs-175", stem: "The velocity ratio (or DVI) for aortic stenosis is calculated as:", options: ["LVOT peak velocity / AV peak velocity — values <0.25 indicate severe AS","AV peak velocity / LVOT peak velocity","Mean gradient / peak gradient","Heart rate / velocity"], correctIndex: 0, rationale: "Velocity ratio = VTI(LVOT)/VTI(AV) or V(LVOT)/V(AV). <0.25 = severe AS. Advantage: independent of LVOT diameter measurement, avoiding area calculation errors.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "AS Assessment" },
  { id: "cs-176", stem: "End-diastolic velocity of the AV regurgitant jet correlates with:", options: ["Aortic diastolic pressure — a lower EDV suggests equalization of aortic and LV diastolic pressures (severe AR)","Systolic pressure","Pulmonary pressure","Heart rate"], correctIndex: 0, rationale: "In AR, as diastolic pressure rapidly equalizes between aorta and LV, the jet velocity decreases rapidly. Short PHT (<200 ms) and low end-diastolic velocity indicate severe acute AR.", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "AR Assessment" },
  { id: "cs-177", stem: "Pulsed wave Doppler aliasing can be eliminated by:", options: ["Increasing PRF (scale), shifting baseline, using CW Doppler, or decreasing transducer frequency","Decreasing PRF","Increasing depth","Increasing frequency"], correctIndex: 0, rationale: "Aliasing solutions: increase PRF (Nyquist limit), shift baseline, use lower frequency transducer, use CW Doppler (no aliasing). If these fail, use CW which has no Nyquist limit.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Doppler Technique" },
  { id: "cs-178", stem: "Peak E-wave velocity is normally:", options: ["0.6-1.3 m/s in healthy adults","Greater than 3.0 m/s","Less than 0.1 m/s","Exactly 2.0 m/s"], correctIndex: 0, rationale: "Normal mitral E velocity: 0.6-1.3 m/s. Increases with elevated LA pressure. Decreases with impaired relaxation. Age-dependent: higher in young adults.", difficulty: 1, category: "Cardiac Hemodynamics & Doppler", topic: "Normal Values" },
  { id: "cs-179", stem: "Pulmonary venous flow systolic blunting indicates:", options: ["Elevated LA pressure — systolic forward flow becomes less than diastolic forward flow","Normal filling","Decreased LA pressure","Pulmonic stenosis"], correctIndex: 0, rationale: "PV systolic blunting (S < D): indicates elevated mean LA pressure. Systolic flow reversal in PV suggests severe MR. Normal pattern: S > D.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Venous Flow" },
  { id: "cs-180", stem: "The 'dagger-shaped' CW Doppler profile in HCM LVOT obstruction shows:", options: ["Late-peaking systolic velocity with a characteristic concave shape due to dynamic obstruction","Early-peaking velocity like AS","Symmetric velocity profile","No detectable velocity"], correctIndex: 0, rationale: "HCM LVOT obstruction CW: 'dagger-shaped' late-systolic peak due to progressive obstruction as the ventricle empties. AS shows early-to-mid peaking. This helps differentiate the two.", difficulty: 3, category: "Valvular Heart Disease", topic: "HCM vs AS" },
  { id: "cs-181", stem: "The Coanda effect in mitral regurgitation refers to:", options: ["An eccentric jet that hugs the wall of the LA, making jet area underestimate severity","A central jet filling the LA","An artifact","Normal valve closure"], correctIndex: 0, rationale: "Coanda effect: eccentric MR jets adhere to the LA wall and appear smaller on color Doppler than their actual severity. PISA, vena contracta, and quantitative methods are more accurate.", difficulty: 2, category: "Valvular Heart Disease", topic: "MR Assessment" },
  { id: "cs-182", stem: "Normal aortic valve area in adults is:", options: ["3.0-4.0 cm²","1.0 cm²","0.5 cm²","6.0 cm²"], correctIndex: 0, rationale: "Normal AVA: 3.0-4.0 cm². Mild AS: AVA >1.5 cm². Moderate: 1.0-1.5 cm². Severe: ≤1.0 cm² (or indexed ≤0.6 cm²/m²).", difficulty: 1, category: "Valvular Heart Disease", topic: "Normal Values" },
  { id: "cs-183", stem: "Functional (secondary) mitral regurgitation is caused by:", options: ["LV dilation/dysfunction causing mitral leaflet tethering and incomplete coaptation, not primary leaflet disease","Primary leaflet pathology","Endocarditis","Rheumatic disease"], correctIndex: 0, rationale: "Functional MR: structurally normal valve with LV remodeling (ischemic or non-ischemic) causing papillary muscle displacement, leaflet tethering, and annular dilation. Different treatment approach.", difficulty: 2, category: "Valvular Heart Disease", topic: "Secondary MR" },
  { id: "cs-184", stem: "Aortic valve stenosis assessment in the presence of aortic regurgitation:", options: ["Requires the continuity equation for AVA calculation, as gradients may overestimate severity due to increased transvalvular flow","Cannot be assessed","Uses only visual assessment","Only uses M-mode"], correctIndex: 0, rationale: "With AR, forward flow volume is increased (forward SV + regurgitant volume), causing higher velocities/gradients than the stenosis alone would produce. Continuity equation provides accurate AVA.", difficulty: 3, category: "Valvular Heart Disease", topic: "Mixed Valve Disease" },
  { id: "cs-185", stem: "The tenting height in functional MR refers to:", options: ["The distance from the annular plane to the coaptation point — increased tenting indicates more tethering","The height of the LA","The thickness of the leaflet","The size of the papillary muscle"], correctIndex: 0, rationale: "Tenting height >11 mm and tenting area >2.5 cm² predict MR recurrence after annuloplasty. These measurements reflect the degree of leaflet tethering from LV remodeling.", difficulty: 3, category: "Valvular Heart Disease", topic: "MR Mechanism" },
  { id: "cs-186", stem: "Mechanical prosthetic valve assessment relies on:", options: ["Doppler hemodynamics (gradients, DVI, EOA), fluoroscopy for leaflet motion, and TEE for complications","Only visual inspection of the valve","Only blood tests","Only chest X-ray"], correctIndex: 0, rationale: "Mechanical valves cause acoustic shadowing limiting TTE. Assessment: Doppler gradients/DVI, fluoroscopy for disc excursion, TEE for regurgitation/pannus/thrombus. Compare to baseline values.", difficulty: 2, category: "Valvular Heart Disease", topic: "Prosthetic Assessment" },
  { id: "cs-187", stem: "Bioprosthetic valve degeneration shows:", options: ["Increased gradients, new/worsening regurgitation, leaflet thickening/calcification, and possible stenosis","Normal hemodynamics","Improved valve function","Decreased gradients"], correctIndex: 0, rationale: "Bioprosthetic degeneration: progressive leaflet thickening, calcification, stenosis (rising gradients), and/or regurgitation. Average lifespan: 10-20 years depending on position and patient age.", difficulty: 2, category: "Valvular Heart Disease", topic: "Prosthetic Valves" },
  { id: "cs-188", stem: "Mitral annular calcification (MAC) on echo appears as:", options: ["Dense echodensity at the mitral annulus, predominantly posterior, with possible acoustic shadowing","Normal mitral annulus","Vegetation on the MV","LA thrombus"], correctIndex: 0, rationale: "MAC: calcium deposition in the mitral annulus (posterior > anterior). Associated with aging, renal disease, and aortic stenosis. May impair MV function or mimic a mass.", difficulty: 1, category: "Valvular Heart Disease", topic: "Mitral Calcification" },
  { id: "cs-189", stem: "Eccentricity index assesses:", options: ["RV pressure or volume overload by measuring LV shape in PSAX — D-shaped septum indicates RV pressure overload","LV ejection fraction","Valve area","Aortic root size"], correctIndex: 0, rationale: "Eccentricity index: D-shaped LV from septal flattening. Systolic flattening = RV pressure overload (pulmonary HTN). Diastolic flattening = RV volume overload (ASD, severe PR/TR).", difficulty: 2, category: "LV Systolic Function Assessment", topic: "RV Assessment" },
  { id: "cs-190", stem: "Cardiac resynchronization therapy (CRT) assessment by echo:", options: ["Evaluates LV dyssynchrony, response to CRT (improved LVEF, reduced LV volumes), and optimal AV/VV delays","Only measures heart rate","Only assesses valve function","Is not used for CRT"], correctIndex: 0, rationale: "Echo assesses CRT candidates (dyssynchrony markers) and response: >10% absolute LVEF increase, >15% reduction in LVESV, clinical improvement. Optimization of AV/VV delays uses Doppler.", difficulty: 3, category: "LV Systolic Function Assessment", topic: "CRT Assessment" },
  { id: "cs-191", stem: "The e' velocity by tissue Doppler is measured at:", options: ["The septal and lateral mitral annulus in the apical 4-chamber view","The aortic valve","The tricuspid valve only","The pulmonic valve"], correctIndex: 0, rationale: "e' measured at the mitral annulus using TDI in A4C. Septal e' ≥7 cm/s and lateral e' ≥10 cm/s are normal. Used with mitral E velocity to calculate E/e'.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "Tissue Doppler" },
  { id: "cs-192", stem: "LV end-diastolic volume (EDV) normal range is approximately:", options: ["56-104 mL (male) or 61-81 mL/m² indexed","200-300 mL","10-20 mL","500 mL"], correctIndex: 0, rationale: "Normal LVEDV varies by gender and body size. Indexed values more accurate: LVEDVI 35-75 mL/m² (men). Elevated EDV indicates LV dilation from volume overload or cardiomyopathy.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "LV Volumes" },
  { id: "cs-193", stem: "A wall motion abnormality graded as 'dyskinesis' means:", options: ["The segment moves outward (paradoxically) during systole — thinning and outward motion","The segment contracts normally","The segment doesn't move","The segment contracts weakly"], correctIndex: 0, rationale: "Dyskinesis: paradoxical outward motion during systole. Indicates transmural scar. Worse than akinesis (no motion). An aneurysm shows dyskinesis with a thin, expanded segment.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "Wall Motion" },
  { id: "cs-194", stem: "Myocardial performance index (Tei index) is abnormal when:", options: ["Greater than 0.40 for the LV or greater than 0.28 for the RV","Less than 0.10","Exactly 0.50 for all patients","Only when LVEF is reduced"], correctIndex: 0, rationale: "Abnormal Tei index indicates combined systolic/diastolic dysfunction. LV >0.40, RV >0.28. Advantage: independent of geometry, preload, and HR. Limitation: affected by PR/MR.", difficulty: 3, category: "LV Systolic Function Assessment", topic: "Global Function" },
  { id: "cs-195", stem: "Normal IVRT (isovolumic relaxation time) ranges from:", options: ["70-90 ms","10-20 ms","200-300 ms","500 ms"], correctIndex: 0, rationale: "Normal IVRT: 70-90 ms. Prolonged (>90 ms): impaired relaxation (Grade I). Short (<60 ms): elevated LA pressure (Grade II-III). Measured from AV closure to MV opening.", difficulty: 2, category: "Diastolic Function Assessment", topic: "IVRT Assessment" },
  { id: "cs-196", stem: "The LA volume should be measured using:", options: ["Biplane area-length or discs method from A4C and A2C views at end-systole (just before MV opening)","M-mode from PLAX","3D only","Subcostal view"], correctIndex: 0, rationale: "LA volume: biplane (A4C + A2C) discs method at end-systole. LA volume index = LA volume / BSA. LAVI >34 mL/m² indicates LA enlargement and chronic diastolic dysfunction.", difficulty: 2, category: "Diastolic Function Assessment", topic: "LA Volume" },
  { id: "cs-197", stem: "Diastolic function grading algorithm uses these four variables:", options: ["Mitral e', average E/e', LAVI, and TR velocity","Only E/A ratio","Only DT","Only IVRT"], correctIndex: 0, rationale: "ASE/EACVI 2016 algorithm: (1) septal e' <7 or lateral e' <10, (2) average E/e' >14, (3) LAVI >34 mL/m², (4) TR velocity >2.8 m/s. ≥3 of 4 abnormal = elevated filling pressure.", difficulty: 2, category: "Diastolic Function Assessment", topic: "Grading Algorithm" },
  { id: "cs-198", stem: "In patients with preserved LVEF, diastolic dysfunction is:", options: ["The primary cause of heart failure symptoms in HFpEF (heart failure with preserved ejection fraction)","Clinically insignificant","Only present in dilated cardiomyopathy","Never associated with symptoms"], correctIndex: 0, rationale: "HFpEF: LVEF ≥50% with diastolic dysfunction causing symptoms (dyspnea, exercise intolerance). Echo diastolic assessment is essential for diagnosis and management.", difficulty: 2, category: "Diastolic Function Assessment", topic: "Clinical Significance" },
  { id: "cs-199", stem: "The 'step-up' in oxygen saturation at a specific cardiac level suggests:", options: ["A left-to-right shunt at that level","A right-to-left shunt","Normal anatomy","Pulmonic stenosis"], correctIndex: 0, rationale: "Oxygen step-up: increased O2 saturation at a level indicates left-to-right shunting. Step-up at RA = ASD, at RV = VSD, at PA = PDA. Quantified by Qp/Qs ratio.", difficulty: 2, category: "Congenital Heart Disease", topic: "Shunt Physiology" },
  { id: "cs-200", stem: "A sinus venosus ASD is located:", options: ["Near the SVC or IVC junction with the RA, often associated with anomalous pulmonary venous return","At the fossa ovalis","At the coronary sinus","In the muscular septum"], correctIndex: 0, rationale: "Sinus venosus ASD: near the SVC-RA junction (superior type, most common) or IVC-RA (inferior type). Often associated with partial anomalous pulmonary venous return (RAPVR).", difficulty: 3, category: "Congenital Heart Disease", topic: "ASD Types" },
  { id: "cs-201", stem: "Perimembranous VSD is located:", options: ["In the membranous septum adjacent to the aortic valve and tricuspid valve","In the muscular septum","In the inlet septum only","In the outlet septum only"], correctIndex: 0, rationale: "Perimembranous (paramembranous) VSD: most common type (~80%). Located in the membranous septum near the AV and TV. May have a windsock aneurysm that partially closes the defect.", difficulty: 2, category: "Congenital Heart Disease", topic: "VSD Types" },
  { id: "cs-202", stem: "Double-outlet right ventricle (DORV) on echo shows:", options: ["Both great arteries arising predominantly from the RV with a VSD","Normal great artery connections","Single ventricle","Only aortic anomaly"], correctIndex: 0, rationale: "DORV: both aorta and PA arise from the RV. Presentation depends on VSD location relative to the great arteries and presence/absence of PS. Variable hemodynamics.", difficulty: 3, category: "Congenital Heart Disease", topic: "Complex CHD" },
  { id: "cs-203", stem: "Truncus arteriosus is characterized by:", options: ["A single great artery arising from the heart that gives rise to the aorta, pulmonary arteries, and coronary arteries","Two normal great arteries","Three great arteries","No great arteries"], correctIndex: 0, rationale: "Truncus arteriosus: single arterial trunk overlies a VSD. The PA(s) arise from the trunk. Common truncal valve may be stenotic or regurgitant. Always with VSD.", difficulty: 3, category: "Congenital Heart Disease", topic: "Complex CHD" },
  { id: "cs-204", stem: "Supracristal (outlet) VSD is:", options: ["Located in the outlet septum below the pulmonic valve, may cause aortic valve prolapse and AR","At the muscular apex","In the membranous septum","At the AV valve level"], correctIndex: 0, rationale: "Supracristal (doubly committed subarterial) VSD: outlet septum beneath both semilunar valves. More common in Asian populations. Risk of aortic cusp prolapse into the VSD causing AR.", difficulty: 3, category: "Congenital Heart Disease", topic: "VSD Types" },
  { id: "cs-205", stem: "Wall motion at peak stress is graded as:", options: ["Normal/hyperkinetic (1), hypokinetic (2), akinetic (3), dyskinetic (4), or aneurysmal (5)","Only pass/fail","Only normal or abnormal","Using Doppler velocities"], correctIndex: 0, rationale: "17-segment model scoring at rest and peak: 1=normal/hyperkinetic, 2=hypokinetic, 3=akinetic, 4=dyskinetic, 5=aneurysmal. New/worsening abnormality = ischemia.", difficulty: 2, category: "Stress Echocardiography", topic: "Scoring" },
  { id: "cs-206", stem: "The RCA territory corresponds to which LV wall segments?", options: ["Inferior, inferoseptal (basal/mid), and RV","Anterior and anteroseptal","Lateral and anterolateral","Apex only"], correctIndex: 0, rationale: "RCA territory: inferior wall (basal/mid), inferoseptal (basal), and RV free wall. RCA also supplies the PDA in right-dominant circulation (~85%).", difficulty: 2, category: "Stress Echocardiography", topic: "Coronary Territories" },
  { id: "cs-207", stem: "Pharmacologic stress with vasodilators (regadenoson/dipyridamole) in echo:", options: ["Is less commonly used for wall motion assessment compared to dobutamine, as vasodilators work primarily by flow maldistribution","Is the preferred echo stress modality","Causes direct myocardial stimulation","Is never used in echocardiography"], correctIndex: 0, rationale: "Vasodilators cause coronary flow maldistribution rather than increased myocardial demand. They are more commonly used with nuclear perfusion imaging. Echo stress prefers exercise or dobutamine.", difficulty: 2, category: "Stress Echocardiography", topic: "Stress Agents" },
  { id: "cs-208", stem: "Resting wall motion abnormality that improves with low-dose dobutamine indicates:", options: ["Viable (hibernating) myocardium — recoverable function with revascularization","Fixed scar","Normal myocardium","Artifact"], correctIndex: 0, rationale: "Hibernating myocardium: chronically dysfunctional but viable. Low-dose dobutamine (5-10 mcg/kg/min) augments contractility in viable segments. Improvement predicts recovery with revascularization.", difficulty: 2, category: "Stress Echocardiography", topic: "Viability" },
  { id: "cs-209", stem: "Friedreich ataxia cardiomyopathy shows:", options: ["Concentric LV hypertrophy (often asymmetric), often with preserved EF initially, and diastolic dysfunction","Dilated cardiomyopathy","Normal heart","Only RV involvement"], correctIndex: 0, rationale: "Friedreich ataxia: most common inherited ataxia. Cardiac involvement in ~75%: concentric or asymmetric LVH, diastolic dysfunction, progressing to systolic dysfunction and HF.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Genetic CMP" },
  { id: "cs-210", stem: "Iron overload cardiomyopathy (hemochromatosis) shows:", options: ["LV dilation with reduced systolic function, often with LVH initially, and characteristic T2* shortening on CMR","Normal echo","Only RV involvement","Only pericardial effusion"], correctIndex: 0, rationale: "Cardiac hemochromatosis: iron deposits cause restrictive then dilated physiology. Echo shows LVH progressing to dilation and systolic dysfunction. CMR T2* <20 ms confirms iron overload.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Infiltrative CMP" },
  { id: "cs-211", stem: "Cardiac sarcoidosis on echo may show:", options: ["Basal septal thinning, regional wall motion abnormalities not following coronary distribution, and possible aneurysm","Normal echo always","Only pericardial effusion","Only valve disease"], correctIndex: 0, rationale: "Cardiac sarcoidosis: patchy granulomatous inflammation. Echo: basal septal thinning, non-coronary RWMAs, possible aneurysm, diastolic dysfunction. CMR/PET more sensitive for diagnosis.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Infiltrative CMP" },
  { id: "cs-212", stem: "Pericardial cyst on echo appears as:", options: ["A well-defined, anechoic, thin-walled cystic structure adjacent to the heart, typically at the right cardiophrenic angle","A solid mass invading the myocardium","A calcified structure","An intracavitary thrombus"], correctIndex: 0, rationale: "Pericardial cysts: benign, fluid-filled, typically at the right cardiophrenic angle. Anechoic, well-defined, and usually asymptomatic. Differentiate from pericardial effusion by location.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Pericardial Masses" },
  { id: "cs-213", stem: "Effusive-constrictive pericarditis shows:", options: ["Features of both pericardial effusion and constriction — elevated filling pressures persist after pericardiocentesis","Only effusion","Only constriction","Normal hemodynamics"], correctIndex: 0, rationale: "Effusive-constrictive: coexisting effusion with underlying visceral pericardial constriction. After draining the effusion, constrictive hemodynamics persist. May progress to pure constriction.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Pericardial Disease" },
  { id: "cs-214", stem: "Peripartum cardiomyopathy develops:", options: ["During the last month of pregnancy or within 5 months postpartum, presenting as dilated cardiomyopathy","Only in elderly patients","Only in men","Only with hypertension"], correctIndex: 0, rationale: "PPCM: new systolic HF (LVEF <45%) developing late in pregnancy or early postpartum without other cause. LV dilation with global hypokinesis. ~50% recover LVEF within 6 months.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Specific CMP" },
  { id: "cs-215", stem: "Hypertensive heart disease on echo shows:", options: ["Concentric LV hypertrophy, diastolic dysfunction, LA enlargement, and eventually systolic dysfunction if untreated","Normal echo","Only dilated LV","Only RV involvement"], correctIndex: 0, rationale: "Hypertensive HD: concentric LVH (wall thickness ≥12 mm), LV mass index increased, diastolic dysfunction (Grade I→III), LA enlargement, and eventually systolic failure if uncontrolled.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Hypertensive HD" },
  { id: "cs-216", stem: "Athlete's heart differs from HCM by:", options: ["Balanced, symmetric hypertrophy (≤13 mm), LV cavity dilation, normal diastolic function, and regression with detraining","Asymmetric hypertrophy with LVOT obstruction","Severely reduced EF","Thickened pericardium"], correctIndex: 0, rationale: "Athlete's heart: mild symmetric LVH (≤13 mm), dilated LV cavity, normal diastolic function (e' normal), no LVOT obstruction, and regression with 3 months of detraining. HCM shows opposite.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Differentiation" },
  { id: "cs-217", stem: "TEE imaging planes include:", options: ["0° (transverse), 45° (short-axis), 90° (longitudinal), and 135° (long-axis views)","Only one plane","Only 0° and 90°","360° continuous rotation"], correctIndex: 0, rationale: "TEE uses a multiplane probe rotating 0°-180°. Key angles: 0° (4-chamber), ~45° (commissural), ~60° (2-chamber), ~90° (LAX), ~120° (3-chamber). Each provides unique information.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "TEE Planes" },
  { id: "cs-218", stem: "Spontaneous echo contrast (SEC or 'smoke') in the LA indicates:", options: ["Stagnant blood flow associated with increased thromboembolic risk, often in atrial fibrillation","Normal blood flow","Active hemorrhage","Artifact"], correctIndex: 0, rationale: "SEC/smoke: swirling echo density from red cell aggregation in areas of stasis. Common in AF with LA enlargement. Grading 0-4. SEC indicates increased stroke/thrombus risk.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "LA Assessment" },
  { id: "cs-219", stem: "The bicaval view on TEE shows:", options: ["The SVC, IVC, and right atrium with the interatrial septum — ideal for PFO/ASD assessment","The LV and RV","The aortic arch","The pulmonary veins"], correctIndex: 0, rationale: "Bicaval TEE view: both vena cavae entering the RA, with IAS in between. Essential for ASD/PFO characterization, sizing, and guiding device closure procedures.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "TEE Views" },
  { id: "cs-220", stem: "TEE assessment before cardioversion for atrial fibrillation:", options: ["Rules out LAA thrombus to reduce stroke risk during cardioversion","Assesses LV function only","Measures aortic valve area","Evaluates coronary arteries"], correctIndex: 0, rationale: "TEE before cardioversion: absence of LAA thrombus/dense SEC allows safe cardioversion. If thrombus present → anticoagulate for ≥3-4 weeks and repeat TEE before attempting.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Clinical Application" },
  { id: "cs-221", stem: "Echo in acute aortic syndrome (dissection) evaluates:", options: ["Intimal flap, true/false lumen, entry tear location, AR, pericardial effusion, and coronary involvement","Only LV function","Only valve gradients","Only pericardial fluid"], correctIndex: 0, rationale: "Aortic dissection echo: intimal flap, true lumen (systolic expansion) vs false lumen (possible thrombus), entry tear, AR mechanism/severity, pericardial effusion (tamponade risk).", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Aortic Emergency" },
  { id: "cs-222", stem: "Right heart catheterization hemodynamic values can be correlated with echo by:", options: ["Comparing echo-derived PASP with RHC PASP, echo E/e' with PCWP, and echo CO with thermodilution CO","No correlation exists","Only comparing heart rate","Only comparing blood pressure"], correctIndex: 0, rationale: "Echo-hemodynamic correlation: PASP from TR velocity vs RHC PASP, E/e' ratio vs PCWP, echo CO (LVOT method) vs thermodilution CO. Good correlation validates echo estimates.", difficulty: 3, category: "TEE & Advanced Techniques", topic: "Echo-Cath Correlation" },
  { id: "cs-223", stem: "Cardiac CT and echo are complementary for:", options: ["CAD assessment, structural planning (TAVI sizing), aortic disease, and when echo windows are poor","They provide identical information","CT replaces all echo","Echo replaces all CT"], correctIndex: 0, rationale: "CT and echo complement each other: CT excels at coronary anatomy, aortic dimensions, TAVI planning, and when echo windows are limited. Echo excels at hemodynamics, real-time function.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Multimodality" },
  { id: "cs-224", stem: "Handheld/point-of-care ultrasound (POCUS) in cardiac assessment:", options: ["Provides focused assessment for pericardial effusion, LV function, and volume status at the bedside","Replaces comprehensive echocardiography","Is only used in research","Has no clinical utility"], correctIndex: 0, rationale: "POCUS: focused cardiac assessment (qualitative LV function, pericardial effusion, IVC for volume status, RV size) at the bedside. Does not replace comprehensive echo but aids rapid clinical decisions.", difficulty: 1, category: "TEE & Advanced Techniques", topic: "POCUS" },
  { id: "cs-225", stem: "In assessing prosthetic valve function, the effective orifice area (EOA) is:", options: ["The functional opening area of the prosthesis during flow — compared to reference values for the specific prosthesis type and size","The anatomic area of the valve ring","The area of the sewing cuff","The area of the annulus before surgery"], correctIndex: 0, rationale: "EOA varies by prosthesis type and size. Measured by continuity equation. Compare to reference ranges. EOA < expected with elevated DVI suggests prosthetic stenosis or patient-prosthesis mismatch.", difficulty: 3, category: "Valvular Heart Disease", topic: "Prosthetic Assessment" },
  { id: "cs-226", stem: "Chiari network on echo appears as:", options: ["A mobile, filamentous structure in the RA — a normal embryologic remnant","A pathologic mass requiring surgery","A thrombus","A vegetation"], correctIndex: 0, rationale: "Chiari network: persistent vestige of the right valve of the sinus venosus. Thin, mobile, fenestrated membrane in RA. Benign normal variant, may be mistaken for pathology.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Normal Variants" },
  { id: "cs-227", stem: "The coronary sinus is best visualized on:", options: ["The PLAX view (posterior AV groove) and the apical 4-chamber view (behind the LA)","The suprasternal view","The subcostal view","The RV inflow view"], correctIndex: 0, rationale: "The coronary sinus courses in the posterior AV groove. Seen as a tubular structure posterior to the LV in PLAX and posterior to the LA in apical views. Dilation suggests PLSVC.", difficulty: 2, category: "Standard Echocardiography Views", topic: "CS Visualization" },
  { id: "cs-228", stem: "Pulsatile hepatic venous flow suggests:", options: ["Severe tricuspid regurgitation causing systolic flow reversal in the hepatic veins","Normal hepatic flow","Hepatic artery stenosis","Portal hypertension"], correctIndex: 0, rationale: "Severe TR: systolic flow reversal in hepatic veins. The transmitted RV pressure causes retrograde flow during systole. This correlates with severe TR on echocardiography.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Right Heart" },
  { id: "cs-229", stem: "The index of myocardial performance (IMP) advantage over LVEF is:", options: ["It assesses both systolic AND diastolic function simultaneously and is relatively preload-independent","It only measures systolic function","It is easier to measure","It replaces all other measurements"], correctIndex: 0, rationale: "IMP (Tei index) reflects global function: prolonged IVCT (systolic) and/or IVRT (diastolic) increase the index. Advantage: geometry-independent, relatively preload-independent.", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "Global Function" },
  { id: "cs-230", stem: "Assessment of mechanical dyssynchrony by echo includes:", options: ["Tissue Doppler velocity timing, speckle tracking strain analysis, and visual assessment of septal flash","Only ECG QRS width","Only chest X-ray","Only clinical symptoms"], correctIndex: 0, rationale: "Echo dyssynchrony assessment: TDI time-to-peak velocity differences, strain timing (radial, longitudinal), septal flash, and apical rocking. Important for CRT candidate selection.", difficulty: 3, category: "LV Systolic Function Assessment", topic: "Dyssynchrony" },
  { id: "cs-231", stem: "The Doppler half-time method for aortic regurgitation:", options: ["PHT <200 ms indicates severe AR — rapid pressure equalization between aorta and LV","PHT >500 ms indicates severe AR","PHT is not applicable to AR","PHT <200 ms is normal"], correctIndex: 0, rationale: "AR PHT: time for peak diastolic gradient to halve. PHT <200 ms = severe (rapid equalization). PHT >500 ms = mild. PHT reflects the rate of aortic diastolic pressure decline.", difficulty: 2, category: "Valvular Heart Disease", topic: "AR Severity" },
  { id: "cs-232", stem: "During intraoperative TEE, the anesthesiologist/sonographer monitors:", options: ["Real-time cardiac function, volume status, surgical results, air embolism, and hemodynamic changes","Only the surgical field","Only blood pressure","Only heart rate"], correctIndex: 0, rationale: "Intraoperative TEE: guides surgical repair assessment (valve repair/replacement, congenital defect closure), monitors LV/RV function, detects air, assesses hemodynamics, and evaluates residual defects.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Intraoperative TEE" },
  { id: "cs-233", stem: "The Lambl excrescence is:", options: ["A thin filamentous strand on valve closure lines — a normal variant that may mimic vegetation","A type of tumor","A thrombus","A calcified nodule"], correctIndex: 0, rationale: "Lambl excrescences are small, mobile, thread-like structures on valve closure lines. Normal degenerative findings, more common with aging. Usually incidental.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Normal Variants" },
  { id: "cs-234", stem: "The crista terminalis is:", options: ["A muscular ridge in the RA separating the smooth-walled sinus venarum from the trabeculated appendage","A structure in the LV","Part of the mitral valve","An aortic structure"], correctIndex: 0, rationale: "The crista terminalis is a prominent muscular ridge in the RA. It can be prominent on echo and mistaken for a mass or thrombus. Normal variant.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Normal Variants" },
  { id: "cs-235", stem: "Normal RV basal diameter in the A4C view is:", options: ["Less than 4.2 cm","Less than 2.0 cm","Greater than 6.0 cm","Exactly 5.0 cm"], correctIndex: 0, rationale: "Normal RV basal diameter <4.2 cm (focused RV A4C view). >4.2 cm = RV dilation. RV:LV ratio >1.0 suggests significant RV dilation.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "RV Dimensions" },
  { id: "cs-236", stem: "The lipomatous hypertrophy of the interatrial septum:", options: ["Is a benign accumulation of adipose tissue in the IAS, sparing the fossa ovalis, creating a 'dumbbell' shape","Is a malignant tumor","Requires surgery","Is invisible on echo"], correctIndex: 0, rationale: "Lipomatous hypertrophy: fatty infiltration of the IAS sparing the fossa ovalis. Creates a bilobed/dumbbell appearance. Benign, common in obese/elderly. Echogenic mass in IAS.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Normal Variants" },
  { id: "cs-237", stem: "M-mode through the aortic valve shows:", options: ["Box-shaped opening in systole and closure in diastole — used to assess cusp separation and timing","Continuous opening","No visible movement","A circular pattern"], correctIndex: 0, rationale: "AV M-mode: box-shaped systolic opening. Reduced cusp separation in AS. Eccentric closure line in BAV. Diastolic flutter of cusps in AR. Useful for timing events.", difficulty: 2, category: "Standard Echocardiography Views", topic: "M-Mode Applications" },
  { id: "cs-238", stem: "Color M-mode propagation velocity (Vp) is used for:", options: ["Assessing diastolic function — Vp <45 cm/s suggests impaired relaxation","Measuring systolic function","Assessing valve stenosis","Measuring cardiac output"], correctIndex: 0, rationale: "Color M-mode Vp measures the velocity of early diastolic flow propagation from MV to apex. Vp <45 cm/s = impaired relaxation. E/Vp ratio >2.5 suggests elevated filling pressure.", difficulty: 3, category: "Diastolic Function Assessment", topic: "Advanced Diastolic" },
  { id: "cs-239", stem: "The Qp/Qs calculation for an ASD uses:", options: ["RVOT SV / LVOT SV — ratio >1.5 indicates hemodynamically significant shunt","Only visual assessment","Only color Doppler","Only bubble study"], correctIndex: 0, rationale: "Qp/Qs = (RVOT CSA × RVOT VTI) / (LVOT CSA × LVOT VTI). >1.5:1 = significant L→R shunt. Helps determine if ASD closure is indicated.", difficulty: 2, category: "Congenital Heart Disease", topic: "Shunt Quantification" },
  { id: "cs-240", stem: "An anomalous left coronary artery from the pulmonary artery (ALCAPA):", options: ["Causes myocardial ischemia as the coronary receives deoxygenated blood at low pressure from the PA","Is a normal variant","Has no clinical significance","Only affects the right coronary artery"], correctIndex: 0, rationale: "ALCAPA: the LCA arises from the PA instead of the aorta. Neonates develop myocardial ischemia, dilated CMP, and MR. Echo shows dilated LCA, abnormal LV function, and reversed flow.", difficulty: 3, category: "Congenital Heart Disease", topic: "Coronary Anomalies" },
  { id: "cs-241", stem: "Shone complex includes:", options: ["Multiple left heart obstructive lesions: supravalvular mitral ring, parachute MV, subaortic stenosis, and coarctation","Only ASD","Only VSD","Only PDA"], correctIndex: 0, rationale: "Shone complex: multiple levels of left heart obstruction. Classic: (1) supravalvular mitral membrane, (2) parachute MV, (3) subaortic stenosis, (4) coarctation of aorta.", difficulty: 3, category: "Congenital Heart Disease", topic: "Complex CHD" },
  { id: "cs-242", stem: "Dextrocardia with situs inversus shows:", options: ["The cardiac apex pointing to the right with mirror-image reversal of all thoracic and abdominal organs","Normal heart position","Only liver reversed","Only spleen reversed"], correctIndex: 0, rationale: "Dextrocardia with situs inversus totalis: mirror-image reversal of all organs. Heart apex points right. Normal cardiac structure (usually). Isolated dextrocardia has higher rate of CHD.", difficulty: 2, category: "Congenital Heart Disease", topic: "Positional Anomalies" },
  { id: "cs-243", stem: "Williams syndrome is associated with:", options: ["Supravalvular aortic stenosis and peripheral pulmonary artery stenosis","Only VSD","Normal cardiac anatomy","Only ASD"], correctIndex: 0, rationale: "Williams syndrome: supravalvular AS (hourglass narrowing above the AV), peripheral PA stenosis, and possible coronary ostial stenosis. Caused by elastin gene deletion.", difficulty: 3, category: "Congenital Heart Disease", topic: "Syndromic CHD" },
  { id: "cs-244", stem: "Noonan syndrome is associated with:", options: ["Pulmonic valve dysplasia/stenosis and hypertrophic cardiomyopathy","Only ASD","Only VSD","Normal cardiac anatomy"], correctIndex: 0, rationale: "Noonan syndrome: pulmonic valve dysplasia (thick, immobile leaflets), HCM, ASD, and various other cardiac anomalies. 'Male Turner syndrome' (but can affect both sexes).", difficulty: 3, category: "Congenital Heart Disease", topic: "Syndromic CHD" },
  { id: "cs-245", stem: "The 'snowman sign' or 'figure-of-8 sign' on chest X-ray is associated with:", options: ["Total anomalous pulmonary venous return (TAPVR) — supracardiac type","Normal cardiac anatomy","Pericardial effusion","Aortic dissection"], correctIndex: 0, rationale: "TAPVR supracardiac type: PVs drain to a vertical vein → innominate → SVC instead of LA. CXR shows snowman sign from dilated vertical vein, innominate, and SVC.", difficulty: 3, category: "Congenital Heart Disease", topic: "TAPVR" },
  { id: "cs-246", stem: "Post-cardiac surgery assessment by echo evaluates:", options: ["LV/RV function, valve repair/replacement results, pericardial effusion, and regional wall motion","Only heart rate","Only blood pressure","Only respiratory rate"], correctIndex: 0, rationale: "Post-surgical echo: LV/RV systolic function, new RWMAs, valve repair assessment (residual regurgitation), prosthetic valve function, pericardial effusion/tamponade, and hemodynamics.", difficulty: 2, category: "Stress Echocardiography", topic: "Post-Surgical" },
  { id: "cs-247", stem: "Stress cardiomyopathy (Takotsubo) recovery typically occurs within:", options: ["Days to weeks, with most patients recovering LVEF within 1-4 weeks","Never — it is permanent","6-12 months","Only with surgical intervention"], correctIndex: 0, rationale: "Takotsubo: transient condition with LV recovery typically within 1-4 weeks. Follow-up echo shows normalization of wall motion and LVEF. Recurrence rate is 2-5% per year.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Prognosis" },
  { id: "cs-248", stem: "Radiation-induced heart disease on echo may show:", options: ["Pericardial thickening/constriction, valvular disease, coronary artery disease, and myocardial fibrosis","Normal echo","Only pericardial effusion","Only valve disease"], correctIndex: 0, rationale: "Radiation heart disease: affects all cardiac structures. Pericarditis/constriction (most common), valvular thickening/regurgitation/stenosis, coronary disease, and myocardial fibrosis.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Radiation CMP" },
  { id: "cs-249", stem: "Cardiac involvement in Fabry disease shows:", options: ["Concentric LVH, especially of the posterior wall, with reduced GLS in the posterolateral segments","Normal echo","Dilated cardiomyopathy","Only RV involvement"], correctIndex: 0, rationale: "Fabry disease: X-linked lysosomal storage disease. Cardiac: progressive concentric LVH (may mimic HCM). Strain shows reduced posterolateral GLS. Enzyme replacement therapy available.", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Storage Disease" },
  { id: "cs-250", stem: "Assessment of the aorta by echo should include:", options: ["Aortic root (sinuses of Valsalva), sinotubular junction, ascending aorta, arch (suprasternal), and proximal descending","Only the aortic valve","Only the ascending aorta","Only the root"], correctIndex: 0, rationale: "Aortic measurements: annulus (PLAX, systole), sinuses of Valsalva, STJ, and ascending aorta (PLAX, diastole). Arch from suprasternal. Descending from TEE or suprasternal.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Aortic Assessment" },
  { id: "cs-251", stem: "The normal aortic root diameter at the sinuses of Valsalva should be:", options: ["Less than 4.0 cm (or <2.1 cm/m² indexed)","Less than 2.0 cm","Greater than 5.0 cm","Exactly 6.0 cm"], correctIndex: 0, rationale: "Normal sinus of Valsalva: <4.0 cm (varies with age, gender, BSA). Indexed: <2.1 cm/m². Dilation >4.5 cm in BAV or >5.0-5.5 cm otherwise warrants surgical consideration.", difficulty: 2, category: "Cardiac Anatomy & Physiology", topic: "Aortic Dimensions" },
  { id: "cs-252", stem: "Cardiac resynchronization therapy (CRT) response is defined as:", options: ["≥10% absolute increase in LVEF or ≥15% decrease in LVEDV at follow-up echo","Any change in heart rate","No echo changes needed","Only symptom improvement"], correctIndex: 0, rationale: "CRT response criteria: ≥10% absolute LVEF improvement, ≥15% reduction in LVESV (reverse remodeling), and clinical improvement. ~30% are non-responders despite meeting selection criteria.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "CRT Response" },
  { id: "cs-253", stem: "LV apical aneurysm on echo shows:", options: ["A thin-walled, akinetic or dyskinetic apical segment that is dilated compared to the rest of the LV, with possible thrombus","Normal apical wall motion","Thick hypertrophied apex","Calcified apex"], correctIndex: 0, rationale: "LV aneurysm: thin, scarred, akinetic/dyskinetic segment. True aneurysm has a wide neck (vs pseudoaneurysm = narrow neck, rupture risk). Check for mural thrombus.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "LV Aneurysm" },
  { id: "cs-254", stem: "LV pseudoaneurysm differs from true aneurysm by:", options: ["A narrow neck (orifice-to-fundus ratio <0.5), contained rupture, and higher risk of free wall rupture","A wide neck","Normal wall thickness","No clinical significance"], correctIndex: 0, rationale: "Pseudoaneurysm: contained rupture with narrow neck. The wall is pericardium/thrombus, not myocardium. Orifice/fundus <0.5. Surgical emergency due to high rupture risk.", difficulty: 3, category: "LV Systolic Function Assessment", topic: "LV Pseudoaneurysm" },
  { id: "cs-255", stem: "Tissue characterization by echo includes:", options: ["Integrated backscatter, strain imaging, contrast perfusion, and harmonic imaging to differentiate tissue types","Only visual assessment","Only M-mode","Only 2D imaging"], correctIndex: 0, rationale: "Advanced tissue characterization: speckle tracking strain, contrast perfusion, integrated backscatter. These help differentiate scar from viable myocardium and identify infiltrative diseases.", difficulty: 3, category: "TEE & Advanced Techniques", topic: "Advanced Imaging" },
  { id: "cs-256", stem: "Echo artifacts that mimic cardiac masses include:", options: ["Side lobe artifacts, reverberations from prosthetic materials, prominent normal structures, and near-field clutter","Only transducer artifacts","No artifacts mimic masses","Only Doppler artifacts"], correctIndex: 0, rationale: "Mass mimickers: side lobes, near-field clutter, reverberation from prosthetic valves/devices, prominent crista terminalis, eustachian valve, Chiari network, Lambl excrescences.", difficulty: 2, category: "Standard Echocardiography Views", topic: "Artifacts" },
  { id: "cs-257", stem: "McConnell's sign on echo suggests:", options: ["Acute pulmonary embolism — RV free wall akinesis with preserved apical contractility","Chronic RV pressure overload","Normal RV function","LV dysfunction"], correctIndex: 0, rationale: "McConnell's sign: RV free wall akinesis with spared/hyperkinetic RV apex. Relatively specific for acute PE. Not seen in chronic RV pressure overload where the apex is also affected.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "PE Assessment" },
  { id: "cs-258", stem: "The RV/LV ratio in the apical 4-chamber view greater than 1.0 suggests:", options: ["RV dilation — seen in pulmonary hypertension, PE, severe TR, and RV cardiomyopathy","Normal heart","LV dilation","Pericardial effusion"], correctIndex: 0, rationale: "RV/LV ratio >1.0: the RV is larger than the LV in the A4C view. Indicates significant RV dilation. In acute PE, this is an adverse prognostic sign.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "RV Assessment" },
  { id: "cs-259", stem: "D-shaped septum (septal flattening toward the LV) in systole indicates:", options: ["RV pressure overload (pulmonary hypertension)","RV volume overload","Normal septal motion","LV hypertrophy"], correctIndex: 0, rationale: "Systolic septal flattening: RV pressure overload (RVSP approaches LV systolic pressure). Diastolic flattening: RV volume overload (ASD, severe TR/PR). Both create a D-shaped LV in PSAX.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "Septal Motion" },
  { id: "cs-260", stem: "Normal aortic valve peak velocity is:", options: ["Less than 2.0 m/s","Less than 0.5 m/s","Greater than 4.0 m/s","Exactly 3.0 m/s"], correctIndex: 0, rationale: "Normal AV peak velocity <2.0 m/s. Aortic sclerosis: thickening without significant velocity increase (<2.0). Mild AS: 2.0-2.9 m/s. Moderate: 3.0-3.9. Severe: ≥4.0.", difficulty: 1, category: "Valvular Heart Disease", topic: "Normal Values" },
  { id: "cs-261", stem: "Systolic anterior motion (SAM) of the mitral valve can also occur in:", options: ["Hypovolemia, basal septal hypertrophy from any cause, and hyperdynamic LV states — not exclusive to HCM","Only in HCM","Only in dilated CMP","Only with prosthetic valves"], correctIndex: 0, rationale: "SAM is not pathognomonic for HCM. It occurs with hypovolemia, hyper-dynamic states, basal septal bulge from HTN, and post-MV repair. Context determines significance.", difficulty: 2, category: "Valvular Heart Disease", topic: "SAM Differential" },
  { id: "cs-262", stem: "Post-TAVI (transcatheter aortic valve implantation) echo assesses:", options: ["Prosthesis position, valve gradients, paravalvular leak, coronary patency, and LV function","Only the valve position","Only LV function","No echo assessment needed"], correctIndex: 0, rationale: "Post-TAVI echo: prosthesis expansion/position, mean gradient (<20 mmHg expected), DVI, paravalvular regurgitation (mild acceptable), coronary flow, and LV function improvement.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Post-Procedural" },
  { id: "cs-263", stem: "S1Q3T3 pattern on ECG with acute RV dilation on echo suggests:", options: ["Acute massive pulmonary embolism","Normal findings","Chronic COPD","LV infarction"], correctIndex: 0, rationale: "ECG S1Q3T3 + echo showing acute RV dilation, McConnell sign, and D-shaped septum strongly suggests massive PE. PASP may be only mildly elevated (acute RV cannot generate high pressures).", difficulty: 2, category: "LV Systolic Function Assessment", topic: "PE Assessment" },
  { id: "cs-264", stem: "The '60/60 sign' in acute PE on echo refers to:", options: ["RVSP <60 mmHg AND pulmonary acceleration time <60 ms — suggestive of acute rather than chronic PE","RVSP >60 and AccT >60","Normal hemodynamics","LV outflow findings"], correctIndex: 0, rationale: "The 60/60 sign differentiates acute from chronic PE. Acute PE: RV can't generate high pressures (RVSP <60), short PA AccT (<60 ms). Chronic PH: RVSP >60 with hypertrophied RV.", difficulty: 3, category: "LV Systolic Function Assessment", topic: "PE vs Chronic PH" },
  { id: "cs-265", stem: "Cardiac imaging quality is affected by:", options: ["Patient body habitus, lung disease, surgical wounds, chest wall deformities, and cooperation","Only the ultrasound machine","Only the transducer","Only the sonographer's skill"], correctIndex: 0, rationale: "Image quality factors: body habitus (obesity, chest wall edema), lung hyperinflation (COPD), surgical dressings, patient positioning, acoustic windows, and patient cooperation.", difficulty: 1, category: "Standard Echocardiography Views", topic: "Image Quality" },
  { id: "cs-266", stem: "A pacemaker/ICD lead on echo appears as:", options: ["A linear echogenic structure traversing the RA and into the RV apex (or other lead position)","An anechoic structure","Not visible on echo","A solid mass"], correctIndex: 0, rationale: "Pacemaker/ICD leads appear as bright, linear echogenic structures in the RA (atrial lead) and RV (ventricular lead). CRT adds a lead in the coronary sinus/LV.", difficulty: 1, category: "Standard Echocardiography Views", topic: "Device Assessment" },
  { id: "cs-267", stem: "The normal mitral valve area is:", options: ["4.0-6.0 cm²","1.0 cm²","0.5 cm²","10 cm²"], correctIndex: 0, rationale: "Normal MVA: 4.0-6.0 cm². Mild MS: MVA >1.5 cm². Moderate: 1.0-1.5 cm². Severe: <1.0 cm². Measured by planimetry (most accurate), PHT (220/PHT), or continuity equation.", difficulty: 1, category: "Valvular Heart Disease", topic: "Normal Values" },
  { id: "cs-268", stem: "Valvular heart disease in pregnancy requires:", options: ["Careful echo assessment of hemodynamic severity as volume changes may worsen pre-existing lesions","No monitoring","Only monitoring in the third trimester","Only post-delivery assessment"], correctIndex: 0, rationale: "Pregnancy increases blood volume by 30-50% and CO by 30-50%. This can worsen MS, AS, and regurgitant lesions. Serial echo monitoring is essential for moderate-severe disease.", difficulty: 2, category: "Valvular Heart Disease", topic: "Special Populations" },
  { id: "cs-269", stem: "The peak velocity of a normal mitral inflow should be:", options: ["Less than 1.3 m/s for the E wave","Greater than 3.0 m/s","Less than 0.1 m/s","Exactly 2.5 m/s"], correctIndex: 0, rationale: "Normal mitral E velocity: 0.6-1.3 m/s. E velocity >1.5 m/s may suggest MS, severe MR, or other causes of elevated transmitral pressure gradient.", difficulty: 1, category: "Cardiac Hemodynamics & Doppler", topic: "Normal Values" },
  { id: "cs-270", stem: "Echo in the ICU setting is used for:", options: ["Hemodynamic assessment, volume status, cardiac function, tamponade, and guiding interventions","Only routine screening","Only valve assessment","Only arrhythmia monitoring"], correctIndex: 0, rationale: "ICU echo: assess LV/RV function, volume status (IVC), tamponade, valvular complications, new RWMAs, and guide fluid therapy/vasopressors. POCUS for rapid bedside assessment.", difficulty: 1, category: "TEE & Advanced Techniques", topic: "Critical Care Echo" },
  { id: "cs-271", stem: "Global RV function can be assessed by:", options: ["TAPSE, FAC, RV s' velocity, RV free wall strain, and MPI (Tei index)","Only LVEF","Only visual assessment","Only cardiac catheterization"], correctIndex: 0, rationale: "RV function parameters: TAPSE (≥17 mm), FAC (≥35%), RV s' (≥10 cm/s), RV free wall GLS (>-20%), and RV MPI (<0.28). Multiple parameters improve assessment accuracy.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "RV Function" },
  { id: "cs-272", stem: "Endocarditis Duke criteria modified for echo include:", options: ["Vegetation, abscess, new prosthetic valve dehiscence, or new valvular regurgitation as major criteria","Only fever","Only blood cultures","Only joint pain"], correctIndex: 0, rationale: "Modified Duke criteria major echo findings: (1) vegetation — oscillating mass on valve, (2) abscess — thickened heterogeneous perivalvular area, (3) new prosthetic dehiscence, (4) new regurgitation.", difficulty: 2, category: "Valvular Heart Disease", topic: "Endocarditis Diagnosis" },
  { id: "cs-273", stem: "Contrast-enhanced echo for LV opacification improves:", options: ["Endocardial border definition, wall motion assessment accuracy, and LV volume/LVEF measurement in technically difficult studies","Color Doppler only","M-mode only","Nothing — contrast has no benefit"], correctIndex: 0, rationale: "LV contrast opacification: improves endocardial visualization from 80% to >95% of segments. More accurate LVEF, better wall motion assessment, and reduced inter-reader variability.", difficulty: 2, category: "TEE & Advanced Techniques", topic: "Contrast Echo" },
  { id: "cs-274", stem: "The persistence of fetal circulation after birth can cause:", options: ["Right-to-left shunting through the PDA and PFO due to elevated pulmonary vascular resistance","Left-to-right shunting only","No hemodynamic effect","Aortic stenosis"], correctIndex: 0, rationale: "Persistent fetal circulation (persistent pulmonary HTN of the newborn): elevated PVR maintains R→L shunting through PDA and PFO, causing hypoxemia. Echo shows dilated RV and TR.", difficulty: 2, category: "Congenital Heart Disease", topic: "Neonatal" },
  { id: "cs-275", stem: "The normal pulmonary artery acceleration time (AccT) is:", options: ["Greater than 100 ms — shortened AccT suggests pulmonary hypertension","Less than 30 ms","Greater than 500 ms","Exactly 50 ms"], correctIndex: 0, rationale: "Normal PA AccT: >100 ms. AccT <100 ms suggests elevated PA pressure. AccT <60 ms with midsystolic notching indicates significantly elevated PVR. Measured from PW Doppler in RVOT.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "PA Assessment" },
  { id: "cs-276", stem: "Strain rate imaging measures:", options: ["The rate of myocardial deformation (1/s) — more sensitive than strain for detecting acute ischemia","Chamber volumes","Valve areas","Blood flow velocity"], correctIndex: 0, rationale: "Strain rate (SR): the rate of deformation (strain per unit time). More load-independent than strain. Reduced SR detects ischemia earlier than wall motion abnormality.", difficulty: 3, category: "TEE & Advanced Techniques", topic: "Advanced Imaging" },
  { id: "cs-277", stem: "The mitral annular disjunction (MAD) on echo shows:", options: ["Separation between the LA wall and the posterior mitral annulus in systole — associated with MVP and arrhythmias","Normal mitral attachment","Mitral stenosis","Mitral annular calcification"], correctIndex: 0, rationale: "MAD: systolic separation of the posterior mitral annulus from the LA wall. Associated with MVP, MR, and ventricular arrhythmias. Measured in PLAX at end-systole.", difficulty: 3, category: "Valvular Heart Disease", topic: "Mitral Anatomy" },
  { id: "cs-278", stem: "Right ventricular pressure overload causes:", options: ["RV hypertrophy, interventricular septal flattening in systole (D-shaped LV), and TR","LV dilation","Mitral stenosis","Aortic regurgitation"], correctIndex: 0, rationale: "Chronic RV pressure overload (PH): RVH (wall thickness >5 mm), systolic septal flattening, RV dilation (late), TR (functional), and eventually RV failure.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "RV Pressure Overload" },
  { id: "cs-279", stem: "The normal RV free wall thickness is:", options: ["Less than 5 mm","Greater than 10 mm","Less than 1 mm","Exactly 8 mm"], correctIndex: 0, rationale: "Normal RV free wall: <5 mm (measured in subcostal view). RV wall ≥5 mm indicates RV hypertrophy from chronic pressure overload (pulmonary HTN, PS).", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "RV Dimensions" },
  { id: "cs-280", stem: "End-systolic dimension (LVIDs) normal range is:", options: ["2.0-4.0 cm","Less than 1.0 cm","Greater than 6.0 cm","Exactly 5.5 cm"], correctIndex: 0, rationale: "Normal LVIDs: 2.0-4.0 cm. Increased LVIDs with reduced FS indicates LV systolic dysfunction. M-mode measurement at mitral leaflet tips in PLAX.", difficulty: 1, category: "LV Systolic Function Assessment", topic: "LV Dimensions" },
  { id: "cs-281", stem: "Prosthesis-patient mismatch (PPM) occurs when:", options: ["The EOA of the implanted prosthetic valve is too small relative to the patient's body size, causing persistently elevated gradients","The valve is too large","The valve material is incompatible","The valve is placed in the wrong position"], correctIndex: 0, rationale: "PPM: indexed EOA <0.85 cm²/m² (moderate) or <0.65 cm²/m² (severe) for aortic prostheses. Causes persistently elevated gradients despite a normally functioning prosthesis.", difficulty: 3, category: "Valvular Heart Disease", topic: "Prosthetic Valves" },
  { id: "cs-282", stem: "The 17-segment model divides the LV into:", options: ["Basal (6 segments), mid (6 segments), apical (4 segments), and apex cap (1 segment)","4 segments","8 segments","32 segments"], correctIndex: 0, rationale: "17-segment model (AHA): 6 basal, 6 mid-cavity, 4 apical, and 1 apex cap. Each assigned to a coronary territory for ischemia localization. Used for wall motion scoring.", difficulty: 1, category: "LV Systolic Function Assessment", topic: "Segmental Model" },
  { id: "cs-283", stem: "Ascending aorta dilation >5.5 cm in a patient without connective tissue disease typically warrants:", options: ["Surgical intervention (prophylactic aortic replacement)","No intervention","Medical management only","Observation without any follow-up"], correctIndex: 0, rationale: "Surgical thresholds: >5.5 cm for degenerative aneurysm without CTD. >5.0 cm for BAV. >4.5-5.0 cm for Marfan or family history of dissection. Growth >0.5 cm/year also warrants surgery.", difficulty: 2, category: "Valvular Heart Disease", topic: "Aortic Surgery" },
  { id: "cs-284", stem: "The continuity equation assumes:", options: ["Conservation of mass — volumetric flow is equal at two points in series within the heart","Conservation of energy only","No assumptions are needed","Equal velocities at all points"], correctIndex: 0, rationale: "The continuity equation is based on conservation of mass: what flows through the LVOT must flow through the AV. Therefore, ALVOT × VTILVOT = AAV × VTIAV.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Continuity Principle" },
  { id: "cs-285", stem: "Normal stroke volume index (SVI) is:", options: ["35-65 mL/m²","10-15 mL/m²","100-150 mL/m²","Less than 10 mL/m²"], correctIndex: 0, rationale: "Normal SVI: 35-65 mL/m². SVI <35 mL/m² = low flow state. Important in low-flow AS assessment. SVI = SV / BSA.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Normal Values" },
  { id: "cs-286", stem: "Assessment of prosthetic mitral valve function includes measuring:", options: ["Mean gradient, DVI, effective orifice area, and looking for paravalvular/transvalvular regurgitation","Only heart rate","Only blood pressure","Only visual inspection"], correctIndex: 0, rationale: "Prosthetic MV: mean gradient (normal 3-6 mmHg for bioprosthetic, 4-8 for mechanical), DVI, EOA (varies by size), and assessment for regurgitation (small physiologic jets are normal).", difficulty: 2, category: "Valvular Heart Disease", topic: "Prosthetic MV" },
  { id: "cs-287", stem: "Aortic root abscess on echo shows:", options: ["Thickened, heterogeneous, echo-lucent area in the aortic root or intervalvular fibrosa","Normal aortic root","Simple pericardial effusion","LV thrombus"], correctIndex: 0, rationale: "Aortic root abscess: perivalvular complication of endocarditis. Echo shows thickened, heterogeneous area with possible echo-lucent cavity. May cause AV dehiscence and fistula formation.", difficulty: 3, category: "Valvular Heart Disease", topic: "Endocarditis Complication" },
  { id: "cs-288", stem: "Apical hypertrophic cardiomyopathy (apical HCM) on echo shows:", options: ["Marked hypertrophy limited to the LV apex with 'ace of spades' configuration in diastole","Septal hypertrophy only","Normal wall thickness","Only RV involvement"], correctIndex: 0, rationale: "Apical HCM: hypertrophy localized to the LV apex creating an 'ace of spades' shape in A4C. More common in Japanese populations. May not cause LVOT obstruction. Risk of apical aneurysm.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "HCM Variants" },
  { id: "cs-289", stem: "Echo in pulmonary embolism may show all EXCEPT:", options: ["ST elevation on the ECG monitor","RV dilation and dysfunction","Septal bowing toward the LV","Tricuspid regurgitation with elevated PASP"], correctIndex: 0, rationale: "Echo findings in acute PE: RV dilation/dysfunction, septal flattening/bowing, TR with elevated PASP (but often only mildly elevated acutely), McConnell sign. ECG is a separate modality.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "PE Diagnosis" },
  { id: "cs-290", stem: "The response to Valsalva maneuver in diastolic function assessment:", options: ["May unmask pseudonormal filling (E/A reversal occurs when E/A drops by ≥50% with Valsalva)","Has no effect on mitral inflow","Only affects systolic function","Only changes heart rate"], correctIndex: 0, rationale: "Valsalva decreases preload → reduces E velocity. In pseudonormal (Grade II): E/A reverses, revealing underlying impaired relaxation. Irreversible restrictive (Grade IV) shows no change.", difficulty: 3, category: "Diastolic Function Assessment", topic: "Provocative Testing" },
  { id: "cs-291", stem: "Serial echo follow-up for mild aortic stenosis is recommended every:", options: ["3-5 years","Every month","Every week","Every 10 years"], correctIndex: 0, rationale: "AS follow-up intervals: mild (Vpeak 2.0-2.9 m/s) every 3-5 years, moderate (3.0-3.9) every 1-2 years, severe (≥4.0) every 6-12 months, or with symptom change.", difficulty: 2, category: "Valvular Heart Disease", topic: "Follow-Up" },
  { id: "cs-292", stem: "The normal RV-RA gradient from TR jet velocity should be less than:", options: ["30-35 mmHg (TR velocity <2.8 m/s) at rest","60 mmHg","100 mmHg","10 mmHg"], correctIndex: 0, rationale: "Normal PASP <35 mmHg at rest (TR velocity <2.8 m/s + RAP 3 mmHg). PASP 36-50 = mildly elevated. >50 = moderate-severe pulmonary hypertension.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Pulmonary Pressures" },
  { id: "cs-293", stem: "Complications of infective endocarditis detectable by echo include:", options: ["Abscess, fistula, pseudoaneurysm, valve perforation, and flail leaflet","Only vegetation","Only fever","Only positive blood cultures"], correctIndex: 0, rationale: "IE complications on echo: perivalvular abscess, intracardiac fistula, mycotic aneurysm, valve perforation, flail leaflet, chordal rupture, and embolic phenomena.", difficulty: 2, category: "Valvular Heart Disease", topic: "IE Complications" },
  { id: "cs-294", stem: "Severe tricuspid regurgitation criteria include:", options: ["Vena contracta ≥7 mm, EROA ≥0.40 cm², hepatic vein systolic flow reversal, and dense CW signal","VC <3 mm","Faint CW signal","Normal hepatic vein flow"], correctIndex: 0, rationale: "Severe TR: VC ≥7 mm, EROA ≥0.40 cm², dense/triangular CW signal, large coaptation gap, hepatic vein systolic reversal, dilated IVC, and RA/RV dilation.", difficulty: 2, category: "Valvular Heart Disease", topic: "TR Severity" },
  { id: "cs-295", stem: "The diastolic flattening of the interventricular septum indicates:", options: ["Right ventricular volume overload (ASD, severe TR/PR)","LV pressure overload","Normal septal motion","Pericardial constriction"], correctIndex: 0, rationale: "Diastolic septal flattening: RV volume overload pushes the septum toward the LV in diastole. Systolic flattening = RV pressure overload. Both create D-shaped LV in PSAX.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "Septal Assessment" },
  { id: "cs-296", stem: "Color Doppler assessment of valvular regurgitation includes evaluating:", options: ["Jet direction, area, width at vena contracta, and proximal flow convergence (PISA)","Only the color of the jet","Only jet length","Only the number of jets"], correctIndex: 0, rationale: "Color Doppler regurgitation assessment: jet origin, direction (central vs eccentric), width at VC, jet area/LA area ratio, PISA radius, and pulmonary/hepatic vein flow patterns.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Color Doppler Assessment" },
  { id: "cs-297", stem: "The normal thickness of the pericardium on echo is:", options: ["Less than 2 mm (often not well visualized on TTE)","5-10 mm","Greater than 15 mm","Exactly 10 mm"], correctIndex: 0, rationale: "Normal pericardium: <2 mm thick. Often not clearly delineated on TTE. CT and CMR better assess pericardial thickness. Thickening >4 mm suggests inflammation or constriction.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Pericardial Assessment" },
  { id: "cs-298", stem: "The tricuspid annular velocity s' by tissue Doppler reflects:", options: ["RV longitudinal systolic function — normal ≥10 cm/s","LV systolic function","Pulmonic valve function","LA function"], correctIndex: 0, rationale: "Tricuspid annular s' ≥10 cm/s indicates normal RV longitudinal systolic function. Reduced s' (<10 cm/s) suggests RV systolic dysfunction. Obtained from A4C, TDI at lateral TV annulus.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "RV TDI" },
  { id: "cs-299", stem: "The effect of atrial fibrillation on diastolic function assessment:", options: ["Loss of organized atrial contraction eliminates the A wave, requiring alternative parameters (DT, E/e', LAVI)","No effect","Improves assessment","Only affects systolic function"], correctIndex: 0, rationale: "In AF: no A wave, E/A ratio unusable. Rely on: mitral E-wave DT (<160 ms = elevated LA pressure), E/e' ratio, LAVI, and TR velocity for filling pressure estimation.", difficulty: 2, category: "Diastolic Function Assessment", topic: "AF Assessment" },
  { id: "cs-300", stem: "Regadenoson stress testing in echocardiography:", options: ["Is a vasodilator given as a single IV bolus — used when exercise and dobutamine are contraindicated","Is the preferred stress agent","Directly stimulates the myocardium","Is used for valve assessment"], correctIndex: 0, rationale: "Regadenoson: selective A2A adenosine receptor agonist given as single 0.4 mg IV bolus. Vasodilator stress. Used when exercise and dobutamine are contraindicated (e.g., severe asthma, pheochromocytoma).", difficulty: 2, category: "Stress Echocardiography", topic: "Stress Agents" },
  { id: "cs-301", stem: "Marfan syndrome cardiac involvement includes:", options: ["Aortic root dilation, aortic dissection, mitral valve prolapse, and aortic regurgitation","Only ASD","Only VSD","Normal cardiac anatomy"], correctIndex: 0, rationale: "Marfan: fibrillin-1 gene mutation. Cardiac: aortic root dilation (sinuses of Valsalva), aortic dissection risk, MVP with MR, and AR. Monitor aortic dimensions annually.", difficulty: 2, category: "Pericardial Disease & Cardiomyopathies", topic: "Connective Tissue Disease" },
  { id: "cs-302", stem: "The mitral annulus normally descends toward the apex during systole by:", options: ["10-15 mm (measured by MAPSE — mitral annular plane systolic excursion)","1-2 mm","25-30 mm","Does not move"], correctIndex: 0, rationale: "MAPSE: mitral annular descent during systole measured by M-mode. Normal ≥10 mm. Reduced MAPSE indicates impaired LV longitudinal systolic function. Simple and reproducible.", difficulty: 2, category: "LV Systolic Function Assessment", topic: "MAPSE" },
  { id: "cs-303", stem: "Cardiac involvement in systemic sclerosis (scleroderma) may show:", options: ["Pericardial effusion, diastolic dysfunction from myocardial fibrosis, and pulmonary hypertension","Normal echo","Only dilated CMP","Only valve disease"], correctIndex: 0, rationale: "Scleroderma cardiac: myocardial fibrosis (patchy, non-coronary distribution), diastolic dysfunction, pericardial effusion, and PH (from pulmonary fibrosis or pulmonary vascular disease).", difficulty: 3, category: "Pericardial Disease & Cardiomyopathies", topic: "Systemic Disease" },
  { id: "cs-304", stem: "Echo assessment of cardiac output using the LVOT method requires:", options: ["LVOT diameter, LVOT VTI, and heart rate — CO = LVOT area × VTI × HR","Only heart rate","Only blood pressure","Only LVEF"], correctIndex: 0, rationale: "CO = LVOT CSA × LVOT VTI × HR = SV × HR. LVOT CSA = π(d/2)². LVOT diameter from PLAX, VTI from A5C PW Doppler. HR from ECG. Most widely used echo CO method.", difficulty: 2, category: "Cardiac Hemodynamics & Doppler", topic: "Cardiac Output" },
  { id: "cs-305", stem: "Paradoxical low-flow, low-gradient severe AS with preserved LVEF is characterized by:", options: ["AVA ≤1.0 cm², mean gradient <40 mmHg, SVI <35 mL/m², and LVEF ≥50%","High gradients with reduced LVEF","Normal AVA","Mild AS"], correctIndex: 0, rationale: "Paradoxical low-flow AS: severe AS criteria (AVA ≤1.0) with low gradients (<40) despite preserved LVEF (≥50%). Due to small LV cavity, concentric LVH, and reduced stroke volume.", difficulty: 3, category: "Cardiac Hemodynamics & Doppler", topic: "Complex AS" },
  { id: "cs-306", stem: "Normal IVC diameter is:", options: ["Less than 2.1 cm with >50% inspiratory collapse","Greater than 3.0 cm","Less than 0.5 cm","Exactly 2.5 cm"], correctIndex: 0, rationale: "Normal IVC: <2.1 cm with >50% collapse on inspiration → RAP 3 mmHg. <2.1 cm with <50% collapse → RAP 8 mmHg. >2.1 cm with <50% collapse → RAP 15 mmHg.", difficulty: 1, category: "Cardiac Hemodynamics & Doppler", topic: "IVC Assessment" },
  { id: "cs-307", stem: "S1 and S2 heart sounds correspond to:", options: ["Closure of the AV valves (mitral/tricuspid = S1) and semilunar valves (aortic/pulmonic = S2)","Opening of all valves","Only aortic valve events","Only mitral valve events"], correctIndex: 0, rationale: "S1: closure of mitral and tricuspid valves (beginning of systole). S2: closure of aortic and pulmonic valves (end of systole). Timing correlates with M-mode valve motion.", difficulty: 1, category: "Cardiac Anatomy & Physiology", topic: "Heart Sounds" },
  { id: "cs-308", stem: "Persistent truncus arteriosus classification (Van Praagh) is based on:", options: ["The origin and arrangement of the pulmonary arteries from the common trunk","The number of AV valves","The size of the VSD","The type of aortic arch"], correctIndex: 0, rationale: "Van Praagh: Type A1 — PA from common trunk via a short MPA. A2 — branch PAs arise directly from trunk posterolaterally. A3 — one PA from trunk, other via collateral. A4 — with interrupted arch.", difficulty: 3, category: "Congenital Heart Disease", topic: "Truncus Classification" },
  { id: "cs-309", stem: "The normal mitral E/A ratio in a 70-year-old adult is often:", options: ["Less than 1.0 (E/A reversal is common with aging due to impaired relaxation)","Greater than 2.0","Exactly 1.5","Greater than 3.0"], correctIndex: 0, rationale: "Normal aging causes impaired myocardial relaxation, resulting in E/A reversal (<1.0) in many adults over 60-70. This is often 'physiologic' Grade I diastolic dysfunction.", difficulty: 2, category: "Diastolic Function Assessment", topic: "Age-Related Changes" },
  { id: "cs-310", stem: "Aortic valve area by planimetry is best measured in:", options: ["The PSAX view at the aortic valve level during systole — measuring the valve orifice directly","The PLAX view","The A4C view","The subcostal view"], correctIndex: 0, rationale: "AVA planimetry: directly trace the aortic orifice in the PSAX during peak systole. Less common than continuity equation due to calcium shadowing and image quality limitations.", difficulty: 2, category: "Valvular Heart Disease", topic: "AVA Measurement" },
  { id: "cs-311", stem: "Normal E/e' average (septal + lateral / 2) is:", options: ["Less than 8 indicates normal filling pressure","Greater than 20","Less than 1","Exactly 15"], correctIndex: 0, rationale: "E/e' average: <8 = normal LAP, >14 = elevated LAP, 8-14 = indeterminate (use LAVI, TR velocity, and other parameters to determine). This is a cornerstone of diastolic assessment.", difficulty: 2, category: "Diastolic Function Assessment", topic: "E/e' Interpretation" },
];
